{
  "name": "FactoryPro Manufacturing System",
  "description": "A high-fidelity production management system for factories, featuring raw material tracking, multi-stage expanding, silo management, dry-weight production logic, and efficiency reporting."
}

export enum Shift {
  Morning = 'Morning',
  Evening = 'Evening',
  Night = 'Night'
}

export enum SiloType {
  Normal = 'Normal',
  ProductionReady = 'Production Ready',
  Intermediate = 'Intermediate'
}

export interface AuditLog {
  id: string;
  module: string;
  action: 'CREATE' | 'UPDATE' | 'DELETE' | 'ADJUST';
  oldValue: string;
  newValue: string;
  user: string;
  date: string;
  time: string;
}

export interface MasterItem {
  id: string;
  name: string;
  category: 'Finished Goods' | 'Raw Material' | 'Operator' | 'Machine';
  uom?: string;
}

export interface RawMaterialStock {
  materialId: string;
  materialName: string;
  kg: number;
  issuedKg: number;
}

export interface ReceivingEntry {
  id: string;
  materialId: string;
  kg: number;
  date: string;
  timestamp: number;
}

export interface IssueEntry {
  id: string;
  materialId: string;
  kg: number;
  date: string;
  timestamp: number;
}

export interface Silo {
  id: number;
  currentStock: number; // kg
  materialName: string;
  type: SiloType;
}

export interface PreExpandingEntry {
  id: string;
  date: string;
  shift: Shift;
  machine: string;
  materialId: string;
  operatorId: string;
  quantityKg: number;
  outputSiloId: number;
}

export interface SecondExpandingEntry {
  id: string;
  date: string;
  shift: Shift;
  operatorId: string;
  quantityKg: number;
  destSiloId: number;
  isLargeBeads: boolean;
}

export interface ProductionEntry {
  id: string;
  date: string;
  shift: Shift;
  machineId: string;
  operatorId: string;
  siloId: number;
  itemId: string;
  isLargeBeads: boolean;
  goodQty: number;
  damagedQty: number;
  avgWetWeight: number; // For FG
  dryWeight: number; // 94% of avgWetWeight
  totalProdWeight: number;
  damagedWeight: number;
}

export interface FinishedGoodsStock {
  itemId: string;
  stockPieces: number;
  totalWeight: number;
}

export interface FuelEntry {
  id: string;
  date: string;
  shift: Shift;
  opening: number;
  purchased: number;
  closing: number;
  used: number;
  totalProdWeightOnDate: number;
}

export interface FactoryState {
  masterItems: MasterItem[];
  rawMaterialStock: RawMaterialStock[];
  receivingLogs: ReceivingEntry[];
  issueLogs: IssueEntry[];
  silos: Silo[];
  siloOpeningSet: boolean;
  preExpandingLogs: PreExpandingEntry[];
  secondExpandingLogs: SecondExpandingEntry[];
  productionLogs: ProductionEntry[];
  fgStock: FinishedGoodsStock[];
  fgOpeningSet: boolean;
  fuelLogs: FuelEntry[];
  auditLogs: AuditLog[];
}

import { SiloType, Shift } from './types';

export const TOTAL_SILOS = 13;
export const MAX_SILO_CAPACITY = 500; // kg
export const DRY_WEIGHT_RATIO = 0.94;
export const BAG_CONVERSION_FACTOR = 25; // 25kg per bag
export const TARGET_FUEL_RATIO = 1.1; // L/kg

export const PRE_EXPANDER_MACHINES = ['Pre Expander 1', 'Pre Expander 2'];
export const SHIFTS: Shift[] = [Shift.Morning, Shift.Evening, Shift.Night];

export const SILO_CONFIGS: Record<number, { type: SiloType }> = {
  5: { type: SiloType.ProductionReady },
  10: { type: SiloType.Intermediate },
};

for (let i = 1; i <= TOTAL_SILOS; i++) {
  if (!SILO_CONFIGS[i]) {
    SILO_CONFIGS[i] = { type: SiloType.Normal };
  }
}

import { FactoryState, SiloType, AuditLog } from './types';
import { TOTAL_SILOS, SILO_CONFIGS } from './constants';

const STORAGE_KEY = 'factory_pro_state_v1';

const initialSilos = Array.from({ length: TOTAL_SILOS }, (_, i) => ({
  id: i + 1,
  currentStock: 0,
  materialName: '',
  type: SILO_CONFIGS[i + 1].type
}));

const initialState: FactoryState = {
  masterItems: [],
  rawMaterialStock: [],
  receivingLogs: [],
  issueLogs: [],
  silos: initialSilos,
  siloOpeningSet: false,
  preExpandingLogs: [],
  secondExpandingLogs: [],
  productionLogs: [],
  fgStock: [],
  fgOpeningSet: false,
  fuelLogs: [],
  auditLogs: []
};

export const loadState = (): FactoryState => {
  const saved = localStorage.getItem(STORAGE_KEY);
  if (!saved) return initialState;
  return JSON.parse(saved);
};

export const saveState = (state: FactoryState) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

export const createAuditLog = (
  module: string,
  action: AuditLog['action'],
  oldValue: string,
  newValue: string
): AuditLog => {
  const now = new Date();
  return {
    id: crypto.randomUUID(),
    module,
    action,
    oldValue,
    newValue,
    user: 'System User', // In a real app, this would be the logged-in user
    date: now.toLocaleDateString(),
    time: now.toLocaleTimeString()
  };
};

import React from 'react';

