const menuItems = [
  'Dashboard',
  'Master Data',
  'Raw Material',
  'Pre Expanding',
  'Silo Management',
  'Production',
  'Finished Goods',
  'Furnace Oil Consumption',
  'Efficiency',
  'Reports'
