import React from 'react';
import { FactoryState } from '../types';
import SiloGraphic from '../components/SiloGraphic';
import { BAG_CONVERSION_FACTOR } from '../constants';

const Dashboard: React.FC<{ state: FactoryState }> = ({ state }) => {
  // Logic for Yesterday Production and Fuel Ratio
  const yesterday = new Date();
  yesterday.setDate(yesterday.getDate() - 1);
  const yesterdayStr = yesterday.toLocaleDateString();

  const yesterdayLogs = state.productionLogs.filter(l => l.date === yesterdayStr);
  const yesterdayFgProd = yesterdayLogs.reduce((acc, l) => acc + (l.isLargeBeads ? 0 : l.totalProdWeight), 0);

  const yesterdayFuelLog = state.fuelLogs.find(l => l.date === yesterdayStr);
  const yesterdayFuelUsed = yesterdayFuelLog ? yesterdayFuelLog.used : 0;
  const yesterdayFuelRatio = yesterdayFgProd > 0 ? (yesterdayFuelUsed / yesterdayFgProd).toFixed(2) : '0.00';

  return (
    <div className="space-y-8">
      {/* Top Summary Row */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4">Raw Material Stock</h3>
          <div className="space-y-3">
            {state.rawMaterialStock.length > 0 ? state.rawMaterialStock.map(rm => (
              <div key={rm.materialId} className="flex justify-between items-center pb-2 border-b border-slate-50">
                <span className="text-sm text-slate-600 font-medium">{rm.materialName}</span>
                <div className="text-right">
                  <div className="text-sm font-bold text-slate-900">{rm.kg.toLocaleString()} kg</div>
                  <div className="text-[10px] text-slate-500">{(rm.kg / BAG_CONVERSION_FACTOR).toFixed(1)} Bags</div>
                </div>
              </div>
            )) : <p className="text-sm text-slate-400 italic">No stock found</p>}
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Yesterday Production</h3>
          <p className="text-3xl font-extrabold text-slate-900">{yesterdayFgProd.toLocaleString()} kg</p>
          <p className="text-xs text-slate-500 mt-1">Total Finished Goods Dry Weight ({yesterdayStr})</p>
        </div>

        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Yesterday Fuel Ratio</h3>
          <p className="text-3xl font-extrabold text-blue-600">{yesterdayFuelRatio} L/kg</p>
          <p className="text-xs text-slate-500 mt-1">Used Fuel / Total FG Weight</p>
        </div>
      </div>

      {/* Silo Grid */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-6">SILO MONITORING (GRID 1–13)</h3>
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-7 gap-4">
          {state.silos.map(silo => (
            <SiloGraphic key={silo.id} silo={silo} />
          ))}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { FactoryState, MasterItem, AuditLog } from '../types';
import { createAuditLog } from '../store';

const MasterData: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [activeCategory, setActiveCategory] = useState<MasterItem['category']>('Finished Goods');
  const [newItemName, setNewItemName] = useState('');

  const handleAdd = () => {
    if (!newItemName.trim()) return;

    const newItem: MasterItem = {
      id: crypto.randomUUID(),
      name: newItemName,
      category: activeCategory
    };

    updateState(prev => {
      const log = createAuditLog('Master Data', 'CREATE', '', `Add ${activeCategory}: ${newItemName}`);

      // If adding Raw Material, initialize stock tracking
      let newRmStock = [...prev.rawMaterialStock];
      if (activeCategory === 'Raw Material') {
        newRmStock.push({
          materialId: newItem.id,
          materialName: newItem.name,
          kg: 0,
          issuedKg: 0
        });
      }

      // If adding FG, initialize FG stock tracking
      let newFgStock = [...prev.fgStock];
      if (activeCategory === 'Finished Goods') {
        newFgStock.push({
          itemId: newItem.id,
          stockPieces: 0,
          totalWeight: 0
        });
      }

      return {
        ...prev,
        masterItems: [...prev.masterItems, newItem],
        rawMaterialStock: newRmStock,
        fgStock: newFgStock,
        auditLogs: [log, ...prev.auditLogs]
      };
    });
    setNewItemName('');
  };

  const handleDelete = (id: string) => {
    updateState(prev => {
      const item = prev.masterItems.find(i => i.id === id);
      const log = createAuditLog('Master Data', 'DELETE', item?.name || '', '');
      return {
        ...prev,
        masterItems: prev.masterItems.filter(i => i.id !== id),
        auditLogs: [log, ...prev.auditLogs]
      };
    });
  };

  const categories: MasterItem['category'][] = ['Finished Goods', 'Raw Material', 'Production Machine', 'Operator'];

  return (
    <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm max-w-4xl">
      <div className="flex space-x-2 mb-8 border-b border-slate-100">
        {categories.map(cat => (
          <button
            key={cat}
            onClick={() => setActiveCategory(cat)}
            className={`px-4 py-2 text-sm font-semibold border-b-2 transition-colors ${
              activeCategory === cat ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-400 hover:text-slate-600'
            }`}
          >
            {cat}
          </button>
        ))}
      </div>

      <div className="flex gap-4 mb-8">
        <input
          type="text"
          value={newItemName}
          onChange={e => setNewItemName(e.target.value)}
          placeholder={`New ${activeCategory} name...`}
          className="flex-1 px-4 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
        <button
          onClick={handleAdd}
          className="px-6 py-2 bg-blue-600 text-white font-semibold rounded-md hover:bg-blue-700"
        >
          Add Item
        </button>
      </div>

      <div className="overflow-hidden border border-slate-200 rounded-lg">
        <table className="w-full text-left">
          <thead className="bg-slate-50">
            <tr>
              <th className="px-6 py-3 text-xs font-bold text-slate-500 uppercase">Name</th>
              <th className="px-6 py-3 text-xs font-bold text-slate-500 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {state.masterItems.filter(i => i.category === activeCategory).map(item => (
              <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 text-sm text-slate-700">{item.name}</td>
                <td className="px-6 py-4 text-sm text-right">
                  <button
                    onClick={() => handleDelete(item.id)}
                    className="text-red-600 hover:text-red-800 font-medium"
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default MasterData;

import React, { useState } from 'react';
import { FactoryState, ReceivingEntry, IssueEntry } from '../types';
import { createAuditLog } from '../store';
import { BAG_CONVERSION_FACTOR } from '../constants';

const RawMaterial: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [selectedRM, setSelectedRM] = useState('');
  const [qty, setQty] = useState<number>(0);
  const [mode, setMode] = useState<'RECEIVING' | 'ISSUE'>('RECEIVING');

  const rawMaterials = state.masterItems.filter(i => i.category === 'Raw Material');

  const handleProcess = () => {
    if (!selectedRM || qty <= 0) return;

    updateState(prev => {
      const rm = rawMaterials.find(r => r.id === selectedRM);
      const stock = prev.rawMaterialStock.find(s => s.materialId === selectedRM);

      if (mode === 'ISSUE' && (!stock || stock.kg < qty)) {
        alert('Insufficient stock for issue!');
        return prev;
      }

      const logMsg = mode === 'RECEIVING' 
        ? `Received ${qty}kg of ${rm?.name}`
        : `Issued ${qty}kg of ${rm?.name}`;

      const auditLog = createAuditLog('Raw Material', mode === 'RECEIVING' ? 'CREATE' : 'CREATE', '', logMsg);

      const entryId = crypto.randomUUID();
      const date = new Date().toLocaleDateString();

      const newRmStock = prev.rawMaterialStock.map(s => {
        if (s.materialId === selectedRM) {
          return {
            ...s,
            kg: mode === 'RECEIVING' ? s.kg + qty : s.kg - qty,
            issuedKg: mode === 'ISSUE' ? s.issuedKg + qty : s.issuedKg
          };
        }
        return s;
      });

      if (mode === 'RECEIVING') {
        const entry: ReceivingEntry = { id: entryId, materialId: selectedRM, kg: qty, date, timestamp: Date.now() };
        return {
          ...prev,
          receivingLogs: [entry, ...prev.receivingLogs],
          rawMaterialStock: newRmStock,
          auditLogs: [auditLog, ...prev.auditLogs]
        };
      } else {
        const entry: IssueEntry = { id: entryId, materialId: selectedRM, kg: qty, date, timestamp: Date.now() };
        return {
          ...prev,
          issueLogs: [entry, ...prev.issueLogs],
          rawMaterialStock: newRmStock,
          auditLogs: [auditLog, ...prev.auditLogs]
        };
      }
    });

    setQty(0);
  };

  return (
    <div className="space-y-8">
      {/* Current Stock Table */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-4">Current Warehouse Stock</h3>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {state.rawMaterialStock.map(rm => (
            <div key={rm.materialId} className="p-4 bg-slate-50 rounded-lg border border-slate-100">
              <div className="text-xs text-slate-500 font-bold uppercase">{rm.materialName}</div>
              <div className="text-xl font-bold text-slate-900">{rm.kg.toLocaleString()} kg</div>
              <div className="text-[10px] text-slate-500">{(rm.kg / BAG_CONVERSION_FACTOR).toFixed(1)} Bags</div>
              <div className="mt-2 text-[10px] bg-blue-100 text-blue-700 inline-block px-2 py-0.5 rounded font-bold uppercase">
                Issued for Expanding: {rm.issuedKg} kg
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Forms */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <div className="flex space-x-4 mb-6">
            <button 
              onClick={() => setMode('RECEIVING')}
              className={`flex-1 py-2 text-sm font-bold rounded-md ${mode === 'RECEIVING' ? 'bg-green-600 text-white' : 'bg-slate-100 text-slate-500'}`}
            >
              Receiving Entry
            </button>
            <button 
              onClick={() => setMode('ISSUE')}
              className={`flex-1 py-2 text-sm font-bold rounded-md ${mode === 'ISSUE' ? 'bg-orange-600 text-white' : 'bg-slate-100 text-slate-500'}`}
            >
              Issue for Expanding
            </button>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Select Raw Material</label>
              <select 
                value={selectedRM}
                onChange={e => setSelectedRM(e.target.value)}
                className="w-full px-4 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="">-- Select Material --</option>
                {rawMaterials.map(rm => (
                  <option key={rm.id} value={rm.id}>{rm.name}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Quantity (kg)</label>
              <input 
                type="number"
                value={qty}
                onChange={e => setQty(Number(e.target.value))}
                className="w-full px-4 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
              <p className="text-[10px] text-slate-400 mt-1">Approx. {(qty / BAG_CONVERSION_FACTOR).toFixed(1)} Bags</p>
            </div>
            <button 
              onClick={handleProcess}
              className={`w-full py-3 rounded-md text-white font-bold transition-opacity hover:opacity-90 ${mode === 'RECEIVING' ? 'bg-green-600' : 'bg-orange-600'}`}
            >
              Submit {mode} Entry
            </button>
          </div>
        </div>

        {/* Audit Log / History Mini-Table */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm overflow-hidden">
          <h3 className="text-sm font-bold text-slate-800 mb-4">Process Audit Log</h3>
          <div className="overflow-y-auto max-h-[300px] text-[10px]">
            <table className="w-full">
              <thead>
                <tr className="border-b border-slate-100">
                  <th className="py-2 text-left text-slate-400 uppercase">Timestamp</th>
                  <th className="py-2 text-left text-slate-400 uppercase">Action</th>
                  <th className="py-2 text-right text-slate-400 uppercase">Detail</th>
                </tr>
              </thead>
              <tbody>
                {state.auditLogs.filter(l => l.module === 'Raw Material').map(log => (
                  <tr key={log.id} className="border-b border-slate-50">
                    <td className="py-2 text-slate-500">{log.date} {log.time}</td>
                    <td className="py-2 font-bold text-slate-700">{log.action}</td>
                    <td className="py-2 text-right text-slate-600 italic">{log.newValue}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default RawMaterial;

import React, { useState } from 'react';
import { FactoryState, PreExpandingEntry, Shift } from '../types';
import { createAuditLog } from '../store';
import { PRE_EXPANDER_MACHINES, SHIFTS, MAX_SILO_CAPACITY } from '../constants';

const PreExpanding: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [form, setForm] = useState({
    shift: Shift.Morning,
    machine: PRE_EXPANDER_MACHINES[0],
    materialId: '',
    operatorId: '',
    quantityKg: 0,
    outputSiloId: 1
  });

  const rawMaterials = state.masterItems.filter(i => i.category === 'Raw Material');
  const operators = state.masterItems.filter(i => i.category === 'Operator');

  const handleProcess = () => {
    if (!form.materialId || !form.operatorId || form.quantityKg <= 0) {
      alert('Fill all required fields!');
      return;
    }

    const issuedStock = state.rawMaterialStock.find(s => s.materialId === form.materialId)?.issuedKg || 0;
    if (form.quantityKg > issuedStock) {
      alert('Not enough issued stock available!');
      return;
    }

    const silo = state.silos.find(s => s.id === form.outputSiloId);
    if (!silo) return;
    if (silo.currentStock + form.quantityKg > MAX_SILO_CAPACITY) {
      alert(`Silo ${form.outputSiloId} capacity exceeded! (Max ${MAX_SILO_CAPACITY}kg)`);
      return;
    }

    updateState(prev => {
      const rm = rawMaterials.find(r => r.id === form.materialId);
      const auditLog = createAuditLog('Pre Expanding', 'CREATE', '', `Pre-expanded ${form.quantityKg}kg of ${rm?.name} into Silo ${form.outputSiloId}`);

      const newEntry: PreExpandingEntry = {
        id: crypto.randomUUID(),
        date: new Date().toLocaleDateString(),
        ...form
      };

      // Update Issued RM Stock
      const newRmStock = prev.rawMaterialStock.map(s => {
        if (s.materialId === form.materialId) {
          return { ...s, issuedKg: s.issuedKg - form.quantityKg };
        }
        return s;
      });

      // Update Silo Stock
      const newSilos = prev.silos.map(s => {
        if (s.id === form.outputSiloId) {
          return {
            ...s,
            currentStock: s.currentStock + form.quantityKg,
            materialName: rm?.name || ''
          };
        }
        return s;
      });

      return {
        ...prev,
        preExpandingLogs: [newEntry, ...prev.preExpandingLogs],
        rawMaterialStock: newRmStock,
        silos: newSilos,
        auditLogs: [auditLog, ...prev.auditLogs]
      };
    });

    setForm({ ...form, quantityKg: 0 });
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider">Process Entry</h3>
        <div className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Shift</label>
              <select 
                value={form.shift}
                onChange={e => setForm({ ...form, shift: e.target.value as Shift })}
                className="w-full px-4 py-2 border border-slate-300 rounded-md bg-slate-50"
              >
                {SHIFTS.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Machine</label>
              <select 
                value={form.machine}
                onChange={e => setForm({ ...form, machine: e.target.value })}
                className="w-full px-4 py-2 border border-slate-300 rounded-md bg-slate-50"
              >
                {PRE_EXPANDER_MACHINES.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Raw Material (Issued)</label>
            <select 
              value={form.materialId}
              onChange={e => setForm({ ...form, materialId: e.target.value })}
              className="w-full px-4 py-2 border border-slate-300 rounded-md"
            >
              <option value="">-- Select Material --</option>
              {rawMaterials.map(rm => {
                const stock = state.rawMaterialStock.find(s => s.materialId === rm.id)?.issuedKg || 0;
                return <option key={rm.id} value={rm.id}>{rm.name} (Avail: {stock} kg)</option>;
              })}
            </select>
          </div>

          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Operator</label>
            <select 
              value={form.operatorId}
              onChange={e => setForm({ ...form, operatorId: e.target.value })}
              className="w-full px-4 py-2 border border-slate-300 rounded-md"
            >
              <option value="">-- Select Operator --</option>
              {operators.map(op => <option key={op.id} value={op.id}>{op.name}</option>)}
            </select>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Quantity (kg)</label>
              <input 
                type="number"
                value={form.quantityKg}
                onChange={e => setForm({ ...form, quantityKg: Number(e.target.value) })}
                className="w-full px-4 py-2 border border-slate-300 rounded-md"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Output Silo</label>
              <select 
                value={form.outputSiloId}
                onChange={e => setForm({ ...form, outputSiloId: Number(e.target.value) })}
                className="w-full px-4 py-2 border border-slate-300 rounded-md"
              >
                {state.silos.map(s => {
                  if (s.id === 10) return null; // Restricted silo 10 from pre-expanding if logic implies
                  return <option key={s.id} value={s.id}>Silo {s.id} ({s.currentStock}kg)</option>;
                })}
              </select>
            </div>
          </div>

          <button 
            onClick={handleProcess}
            className="w-full py-4 bg-slate-800 text-white font-bold rounded-md hover:bg-slate-900 transition-colors mt-4"
          >
            Start Pre-Expanding
          </button>
        </div>
      </div>

      <div className="bg-slate-900 p-8 rounded-xl text-white">
        <h3 className="text-sm font-bold text-slate-400 mb-6 uppercase tracking-wider">Issued Inventory Status</h3>
        <div className="space-y-4">
          {state.rawMaterialStock.map(rm => (
            <div key={rm.materialId} className="flex justify-between items-center border-b border-slate-800 pb-3">
              <div>
                <div className="text-sm font-bold">{rm.materialName}</div>
                <div className="text-[10px] text-slate-500">Ready for expanding process</div>
              </div>
              <div className="text-right">
                <div className="text-xl font-extrabold text-blue-400">{rm.issuedKg} kg</div>
                <div className="text-[10px] text-slate-500">Available</div>
              </div>
            </div>
          ))}
          {state.rawMaterialStock.length === 0 && <p className="text-slate-500 italic text-sm">No raw material stock issued.</p>}
        </div>
      </div>
    </div>
  );
};

export default PreExpanding;

import React, { useState } from 'react';
import { FactoryState, Shift, SiloType } from '../types';
import { createAuditLog } from '../store';
import { SHIFTS, MAX_SILO_CAPACITY } from '../constants';

const SiloManagement: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [openingValues, setOpeningValues] = useState<Record<number, number>>(
    Object.fromEntries(state.silos.map(s => [s.id, s.currentStock]))
  );
  const [adjustment, setAdjustment] = useState({ siloId: 1, qty: 0, reason: '' });
  const [expanding, setExpanding] = useState({ shift: Shift.Morning, operatorId: '', qty: 0, destId: 5, isLargeBeads: false });

  const operators = state.masterItems.filter(i => i.category === 'Operator');

  const handleSetOpening = () => {
    if (state.siloOpeningSet) return;
    updateState(prev => {
      const newSilos = prev.silos.map(s => ({
        ...s,
        currentStock: openingValues[s.id] || 0
      }));
      return {
        ...prev,
        silos: newSilos,
        siloOpeningSet: true,
        auditLogs: [createAuditLog('Silo Management', 'ADJUST', '0', 'Opening Silo Stock Set'), ...prev.auditLogs]
      };
    });
  };

  const handleAdjust = () => {
    if (adjustment.qty === 0) return;
    updateState(prev => {
      const silo = prev.silos.find(s => s.id === adjustment.siloId);
      if (!silo) return prev;
      const newQty = silo.currentStock + adjustment.qty;
      if (newQty < 0 || newQty > MAX_SILO_CAPACITY) {
        alert('Invalid adjustment quantity!');
        return prev;
      }

      const newSilos = prev.silos.map(s => s.id === adjustment.siloId ? { ...s, currentStock: newQty } : s);
      return {
        ...prev,
        silos: newSilos,
        auditLogs: [createAuditLog('Silo Management', 'ADJUST', silo.currentStock.toString(), `Manual Adjustment: ${adjustment.qty}kg - ${adjustment.reason}`), ...prev.auditLogs]
      };
    });
    setAdjustment({ ...adjustment, qty: 0, reason: '' });
  };

  const handleSecondExpand = () => {
    if (expanding.qty <= 0) return;
    const silo10 = state.silos.find(s => s.id === 10);
    const destSilo = state.silos.find(s => s.id === expanding.destId);

    if (!silo10 || silo10.currentStock < expanding.qty) {
      alert('Insufficient stock in Silo 10!');
      return;
    }
    if (!destSilo || destSilo.currentStock + expanding.qty > MAX_SILO_CAPACITY) {
      alert(`Dest Silo ${expanding.destId} capacity exceeded!`);
      return;
    }

    updateState(prev => {
      const newSilos = prev.silos.map(s => {
        if (s.id === 10) return { ...s, currentStock: s.currentStock - expanding.qty };
        if (s.id === expanding.destId) return { ...s, currentStock: s.currentStock + expanding.qty, materialName: silo10.materialName };
        return s;
      });

      return {
        ...prev,
        silos: newSilos,
        secondExpandingLogs: [{ id: crypto.randomUUID(), date: new Date().toLocaleDateString(), ...expanding }, ...prev.secondExpandingLogs],
        auditLogs: [createAuditLog('Silo Management', 'CREATE', '', `Second Expanding: ${expanding.qty}kg Silo 10 -> Silo ${expanding.destId}`), ...prev.auditLogs]
      };
    });
    setExpanding({ ...expanding, qty: 0 });
  };

  return (
    <div className="space-y-8">
      {/* Opening Stock Section */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-4">6A. ONE-TIME OPENING STOCK (SILO)</h3>
        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-7 gap-4 mb-4">
          {state.silos.map(s => (
            <div key={s.id}>
              <label className="text-[10px] font-bold text-slate-500">Silo {s.id} (kg)</label>
              <input
                type="number"
                disabled={state.siloOpeningSet}
                value={openingValues[s.id] || 0}
                onChange={e => setOpeningValues({ ...openingValues, [s.id]: Number(e.target.value) })}
                className="w-full px-2 py-1 border border-slate-200 rounded text-xs disabled:bg-slate-50"
              />
            </div>
          ))}
        </div>
        <button
          onClick={handleSetOpening}
          disabled={state.siloOpeningSet}
          className={`px-6 py-2 rounded-md font-bold text-white ${state.siloOpeningSet ? 'bg-slate-300 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700'}`}
        >
          Set Opening Silo Stock
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Manual Adjustment */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold text-slate-800 mb-4">6B. MANUAL STOCK ADJUSTMENT</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Select Silo</label>
              <select 
                value={adjustment.siloId}
                onChange={e => setAdjustment({ ...adjustment, siloId: Number(e.target.value) })}
                className="w-full px-4 py-2 border border-slate-300 rounded-md"
              >
                {state.silos.map(s => <option key={s.id} value={s.id}>Silo {s.id}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Adjustment (+/- kg)</label>
              <input 
                type="number"
                value={adjustment.qty}
                onChange={e => setAdjustment({ ...adjustment, qty: Number(e.target.value) })}
                className="w-full px-4 py-2 border border-slate-300 rounded-md"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Reason</label>
              <input 
                type="text"
                value={adjustment.reason}
                onChange={e => setAdjustment({ ...adjustment, reason: e.target.value })}
                className="w-full px-4 py-2 border border-slate-300 rounded-md"
                placeholder="Spillage, cleaning, etc."
              />
            </div>
            <button onClick={handleAdjust} className="w-full py-2 bg-slate-700 text-white font-bold rounded-md">Adjust Silo Stock</button>
          </div>
        </div>

        {/* Second Expanding */}
        <div className="bg-blue-50 p-6 rounded-xl border border-blue-200 shadow-sm">
          <h3 className="text-sm font-bold text-blue-900 mb-4">6C. SECOND EXPANDING PROCESS (SILO 10 ONLY)</h3>
          <div className="space-y-4">
            <div className="flex items-center justify-between p-3 bg-white border border-blue-200 rounded-lg">
              <span className="text-sm font-bold text-slate-600">Source Silo: 10 (Intermediate)</span>
              <span className="text-lg font-extrabold text-blue-600">{state.silos.find(s => s.id === 10)?.currentStock} kg</span>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 mb-1">Dest Silo (OUT)</label>
                <select 
                  value={expanding.destId}
                  onChange={e => setExpanding({ ...expanding, destId: Number(e.target.value) })}
                  className="w-full px-4 py-2 border border-blue-200 rounded-md"
                >
                  <option value={5}>Silo 5 (Production Ready)</option>
                  <option value={7}>Silo 7 (Normal)</option>
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 mb-1">Quantity (kg)</label>
                <input 
                  type="number"
                  value={expanding.qty}
                  onChange={e => setExpanding({ ...expanding, qty: Number(e.target.value) })}
                  className="w-full px-4 py-2 border border-blue-200 rounded-md"
                />
              </div>
            </div>
            <div className="flex items-center space-x-2">
              <input 
                type="checkbox" 
                id="largeBeads"
                checked={expanding.isLargeBeads}
                onChange={e => setExpanding({...expanding, isLargeBeads: e.target.checked})}
              />
              <label htmlFor="largeBeads" className="text-sm font-bold text-slate-700">6D. Mark as Large Expanding Beads</label>
            </div>
            <button onClick={handleSecondExpand} className="w-full py-3 bg-blue-600 text-white font-bold rounded-md hover:bg-blue-700">Process Second Expanding</button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SiloManagement;

import React, { useState } from 'react';
import { FactoryState, Shift, ProductionEntry } from '../types';
import { createAuditLog } from '../store';
import { SHIFTS, DRY_WEIGHT_RATIO } from '../constants';

const Production: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [form, setForm] = useState({
    shift: Shift.Morning,
    machineId: '',
    operatorId: '',
    siloId: 1,
    itemId: '',
    goodQty: 0,
    damagedQty: 0,
    avgWetWeight: 0,
    isLargeBeads: false
  });

  const fgItems = state.masterItems.filter(i => i.category === 'Finished Goods');
  const operators = state.masterItems.filter(i => i.category === 'Operator');
  const machines = state.masterItems.filter(i => i.category === 'Production Machine');

  const handleProduction = () => {
    if (!form.operatorId || !form.machineId || !form.itemId) {
      alert('Required fields missing!');
      return;
    }

    const totalQty = form.goodQty + form.damagedQty;
    const dryWeight = form.isLargeBeads ? 1 : (form.avgWetWeight * DRY_WEIGHT_RATIO);
    const totalProdWeight = totalQty * (form.isLargeBeads ? 1 : dryWeight);
    const damagedWeight = form.damagedQty * (form.isLargeBeads ? 1 : dryWeight);

    const silo = state.silos.find(s => s.id === form.siloId);
    if (!silo || silo.currentStock < totalProdWeight) {
      alert(`Insufficient stock in Silo ${form.siloId}! Needs ${totalProdWeight.toFixed(2)}kg`);
      return;
    }

    updateState(prev => {
      const entry: ProductionEntry = {
        id: crypto.randomUUID(),
        date: new Date().toLocaleDateString(),
        ...form,
        dryWeight,
        totalProdWeight,
        damagedWeight
      };

      // Deduct from Silo
      const newSilos = prev.silos.map(s => s.id === form.siloId ? { ...s, currentStock: s.currentStock - totalProdWeight } : s);

      // Add to FG Stock if not large beads
      let newFgStock = [...prev.fgStock];
      if (!form.isLargeBeads) {
        newFgStock = prev.fgStock.map(s => {
          if (s.itemId === form.itemId) {
            return {
              ...s,
              stockPieces: s.stockPieces + form.goodQty,
              totalWeight: s.totalWeight + (form.goodQty * dryWeight)
            };
          }
          return s;
        });
      }

      const logMsg = `Production: ${totalQty} units of ${fgItems.find(i => i.id === form.itemId)?.name} from Silo ${form.siloId}`;
      const auditLog = createAuditLog('Production', 'CREATE', '', logMsg);

      return {
        ...prev,
        productionLogs: [entry, ...prev.productionLogs],
        silos: newSilos,
        fgStock: newFgStock,
        auditLogs: [auditLog, ...prev.auditLogs]
      };
    });

    setForm({ ...form, goodQty: 0, damagedQty: 0, avgWetWeight: 0 });
  };

  return (
    <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1">Date</label>
          <input type="text" disabled value={new Date().toLocaleDateString()} className="w-full px-4 py-2 border border-slate-200 rounded bg-slate-50 text-slate-400" />
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1">Shift</label>
          <select value={form.shift} onChange={e => setForm({...form, shift: e.target.value as Shift})} className="w-full px-4 py-2 border border-slate-300 rounded">
            {SHIFTS.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1">Machine</label>
          <select value={form.machineId} onChange={e => setForm({...form, machineId: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded">
            <option value="">-- Select --</option>
            {machines.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1">Operator</label>
          <select value={form.operatorId} onChange={e => setForm({...form, operatorId: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded">
            <option value="">-- Select --</option>
            {operators.map(o => <option key={o.id} value={o.id}>{o.name}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1">Source Silo (Exclude 10)</label>
          <select value={form.siloId} onChange={e => setForm({...form, siloId: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded">
            {state.silos.filter(s => s.id !== 10).map(s => <option key={s.id} value={s.id}>Silo {s.id} ({s.currentStock}kg)</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1">Production Type</label>
          <div className="flex items-center space-x-4 h-[42px]">
            <label className="flex items-center space-x-2 text-sm font-medium">
              <input type="radio" checked={!form.isLargeBeads} onChange={() => setForm({...form, isLargeBeads: false})} />
              <span>Finished Goods</span>
            </label>
            <label className="flex items-center space-x-2 text-sm font-medium">
              <input type="radio" checked={form.isLargeBeads} onChange={() => setForm({...form, isLargeBeads: true})} />
              <span>Large Beads (kg)</span>
            </label>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 border-t border-slate-100 pt-8">
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1">Item Selection</label>
          <select value={form.itemId} onChange={e => setForm({...form, itemId: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded">
            <option value="">-- Select Item --</option>
            {fgItems.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1">Good Quantity</label>
          <input type="number" value={form.goodQty} onChange={e => setForm({...form, goodQty: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" />
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1">Damaged Quantity</label>
          <input type="number" value={form.damagedQty} onChange={e => setForm({...form, damagedQty: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" />
        </div>
        {!form.isLargeBeads && (
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Average Wet Weight (kg/pc)</label>
            <input type="number" step="0.001" value={form.avgWetWeight} onChange={e => setForm({...form, avgWetWeight: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" />
          </div>
        )}
      </div>

      {!form.isLargeBeads && form.avgWetWeight > 0 && (
        <div className="mt-4 p-4 bg-slate-50 rounded-lg flex space-x-8">
          <div>
            <span className="text-xs text-slate-500 font-bold">DRY WEIGHT:</span>
            <span className="ml-2 text-sm font-bold text-blue-600">{(form.avgWetWeight * DRY_WEIGHT_RATIO).toFixed(3)} kg</span>
          </div>
          <div>
            <span className="text-xs text-slate-500 font-bold">TOTAL PROD WEIGHT:</span>
            <span className="ml-2 text-sm font-bold text-blue-600">{((form.goodQty + form.damagedQty) * (form.avgWetWeight * DRY_WEIGHT_RATIO)).toFixed(2)} kg</span>
          </div>
        </div>
      )}

      <button onClick={handleProduction} className="mt-8 w-full py-4 bg-slate-900 text-white font-bold rounded-md hover:bg-black transition-colors uppercase">
        Record Production Entry
      </button>
    </div>
  );
};

