                    <td className="px-4 py-3">{machineName}</td>
                    <td className="px-4 py-3 text-green-600 font-bold">{log.goodQty.toLocaleString()}</td>
                    <td className="px-4 py-3 text-red-600">{log.damagedQty.toLocaleString()}</td>
                    <td className="px-4 py-3">{log.avgWetWeight.toFixed(3)}</td>
                    <td className="px-4 py-3 font-bold">{log.dryWeight.toFixed(3)}</td>
                    <td className="px-4 py-3 text-right font-black text-blue-600">{log.totalProdWeight.toFixed(2)}</td>
                  </tr>
                );
              })}
              {filteredLogs.length === 0 && (
                <tr>
                  <td colSpan={9} className="px-4 py-8 text-center text-slate-400 italic">No production logs found matching criteria.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Reports;

