import React, { useState } from 'react';
import { FactoryState } from '../types';
import { createAuditLog } from '../store';

const FinishedGoods: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [openingValues, setOpeningValues] = useState<Record<string, { pcs: number; weight: number }>>({});
  const [adjustment, setAdjustment] = useState({ itemId: '', qty: 0, reason: '', date: new Date().toISOString().split('T')[0] });

  const fgItems = state.masterItems.filter(i => i.category === 'Finished Goods');
  const hasProductionRecords = state.productionLogs.length > 0;

  const handleSetOpening = () => {
    if (state.fgOpeningSet) {
      alert('Opening stock already set.');
      return;
    }
    if (hasProductionRecords) {
      alert('Cannot set opening stock after production has started.');
      return;
    }

    // Validate non-negative values
    const values = Object.values(openingValues);
    if (values.some(v => v.pcs < 0 || v.weight < 0)) {
      alert('Stock values cannot be negative.');
      return;
    }

    updateState(prev => {
      const newFgStock = prev.fgStock.map(s => {
        const ov = openingValues[s.itemId];
        if (ov) {
          return { ...s, stockPieces: ov.pcs, totalWeight: ov.weight };
        }
        return s;
      });
      return {
        ...prev,
        fgStock: newFgStock,
        fgOpeningSet: true,
        auditLogs: [createAuditLog('Finished Goods', 'ADJUST', '0', 'Opening FG Stock Set Permanently'), ...prev.auditLogs]
      };
    });
  };

  const handleAdjust = () => {
    if (!adjustment.itemId || adjustment.qty === 0 || !adjustment.date) {
      alert('Enter quantity, item, and date.');
      return;
    }
    updateState(prev => {
      const stock = prev.fgStock.find(s => s.itemId === adjustment.itemId);
      if (!stock) return prev;
      if (stock.stockPieces + adjustment.qty < 0) {
        alert('Negative stock not allowed!');
        return prev;
      }

      const formattedDate = new Date(adjustment.date).toLocaleDateString();
      const newFgStock = prev.fgStock.map(s => s.itemId === adjustment.itemId ? { ...s, stockPieces: s.stockPieces + adjustment.qty } : s);
      return {
        ...prev,
        fgStock: newFgStock,
        auditLogs: [createAuditLog('Finished Goods', 'ADJUST', stock.stockPieces.toString(), `Manual Adjustment: ${adjustment.qty} pcs on ${formattedDate} - ${adjustment.reason}`), ...prev.auditLogs]
      };
    });
    setAdjustment({ ...adjustment, qty: 0, reason: '' });
  };

  return (
    <div className="space-y-8">
      {/* Stock Display */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider">Finished Goods Inventory</h3>
        <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-6">
          {state.fgStock.map(s => {
            const item = fgItems.find(i => i.id === s.itemId);
            return (
              <div key={s.itemId} className="p-4 bg-slate-50 border border-slate-100 rounded-lg">
                <div className="text-xs font-bold text-slate-400 uppercase truncate">{item?.name}</div>
                <div className="text-2xl font-extrabold text-slate-900">{s.stockPieces.toLocaleString()} <span className="text-xs text-slate-400 font-normal">Pcs</span></div>
                <div className="text-xs text-blue-600 font-bold mt-1">Weight: {s.totalWeight.toFixed(2)} kg</div>
              </div>
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Opening Stock */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">8A. ONE-TIME OPENING STOCK</h3>
          <p className="text-[10px] text-slate-400 mb-4">* Allowed only if NO production records exist.</p>
          <div className="max-h-[300px] overflow-y-auto mb-4 border border-slate-100 rounded">
            <table className="w-full text-xs text-left">
              <thead className="bg-slate-50 sticky top-0">
                <tr>
                  <th className="px-3 py-2">Item</th>
                  <th className="px-3 py-2">Pcs</th>
                  <th className="px-3 py-2">Weight (kg)</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {fgItems.map(item => (
                  <tr key={item.id}>
                    <td className="px-3 py-2">{item.name}</td>
                    <td className="px-3 py-2">
                      <input 
                        type="number" 
                        disabled={state.fgOpeningSet || hasProductionRecords}
                        value={openingValues[item.id]?.pcs || 0}
                        onChange={e => setOpeningValues({...openingValues, [item.id]: { ...(openingValues[item.id] || {weight: 0}), pcs: Number(e.target.value) }})}
                        className="w-full px-2 py-1 border border-slate-200 rounded"
                      />
                    </td>
                    <td className="px-3 py-2">
                       <input 
                        type="number" 
                        disabled={state.fgOpeningSet || hasProductionRecords}
                        value={openingValues[item.id]?.weight || 0}
                        onChange={e => setOpeningValues({...openingValues, [item.id]: { ...(openingValues[item.id] || {pcs: 0}), weight: Number(e.target.value) }})}
                        className="w-full px-2 py-1 border border-slate-200 rounded"
                      />
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <button 
            onClick={handleSetOpening}
            disabled={state.fgOpeningSet || hasProductionRecords}
            className={`w-full py-2 rounded font-bold text-white transition-colors ${state.fgOpeningSet || hasProductionRecords ? 'bg-slate-300 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700'}`}
          >
            {state.fgOpeningSet ? 'Opening Stock Already Set' : hasProductionRecords ? 'Production Exist - Opening Blocked' : 'Set Opening Finished Goods Stock'}
          </button>
        </div>

        {/* Adjustments */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">8B. MANUAL STOCK ADJUSTMENT</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Date (Mandatory)</label>
              <input 
                type="date" 
                required
                value={adjustment.date}
                onChange={e => setAdjustment({...adjustment, date: e.target.value})}
                className="w-full px-4 py-2 border border-slate-300 rounded"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Select Item</label>
              <select 
                value={adjustment.itemId}
                onChange={e => setAdjustment({...adjustment, itemId: e.target.value})}
                className="w-full px-4 py-2 border border-slate-300 rounded"
              >
                <option value="">-- Select --</option>
                {fgItems.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Quantity Adjustment (+ / - Pcs)</label>
              <input 
                type="number" 
                value={adjustment.qty}
                onChange={e => setAdjustment({...adjustment, qty: Number(e.target.value)})}
                className="w-full px-4 py-2 border border-slate-300 rounded"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Reason</label>
              <input 
                type="text" 
                value={adjustment.reason}
                onChange={e => setAdjustment({...adjustment, reason: e.target.value})}
                className="w-full px-4 py-2 border border-slate-300 rounded"
                placeholder="Dispatches, returns, etc."
              />
            </div>
            <button onClick={handleAdjust} className="w-full py-2 bg-slate-800 text-white font-bold rounded">Adjust Finished Goods Stock</button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FinishedGoods;

import React, { useState } from 'react';
import { FactoryState, Shift, FuelEntry } from '../types';
import { createAuditLog } from '../store';
import { SHIFTS } from '../constants';

const FuelConsumption: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [form, setForm] = useState({
    date: new Date().toISOString().split('T')[0],
    shift: Shift.Day,
    opening: 0,
    purchased: 0,
    closing: 0
  });

  const handleFuelEntry = () => {
    const used = form.opening + form.purchased - form.closing;
    if (used < 0) {
      alert('Invalid consumption calculation (Closing > Opening + Purchased)!');
      return;
    }
    if (!form.date) {
      alert('Date is mandatory.');
      return;
    }

    const formattedDate = new Date(form.date).toLocaleDateString();
    const todaysProd = state.productionLogs
      .filter(l => l.date === formattedDate)
      .reduce((acc, l) => acc + l.totalProdWeight, 0);

    updateState(prev => {
      const entry: FuelEntry = {
        id: crypto.randomUUID(),
        ...form,
        date: formattedDate,
        used,
        totalProdWeightOnDate: todaysProd
      };

      return {
        ...prev,
        fuelLogs: [entry, ...prev.fuelLogs],
        auditLogs: [createAuditLog('Fuel Consumption', 'CREATE', '', `Fuel Entry: ${used}L used on ${formattedDate}`), ...prev.auditLogs]
      };
    });
    setForm({ ...form, purchased: 0 });
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider">Consumption Entry</h3>
        <div className="space-y-4">
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Date (Mandatory)</label>
            <input 
              type="date"
              required
              value={form.date}
              onChange={e => setForm({...form, date: e.target.value})}
              className="w-full px-4 py-2 border border-slate-300 rounded"
            />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Shift</label>
            <select value={form.shift} onChange={e => setForm({...form, shift: e.target.value as Shift})} className="w-full px-4 py-2 border border-slate-300 rounded">
              {SHIFTS.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
          <div className="grid grid-cols-3 gap-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Opening (L)</label>
              <input type="number" value={form.opening} onChange={e => setForm({...form, opening: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Purchased (L)</label>
              <input type="number" value={form.purchased} onChange={e => setForm({...form, purchased: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1">Closing (L)</label>
              <input type="number" value={form.closing} onChange={e => setForm({...form, closing: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" />
            </div>
          </div>
          <div className="p-4 bg-amber-50 rounded-lg flex justify-between items-center">
            <span className="text-xs font-bold text-amber-700 uppercase">Calculated Consumption:</span>
            <span className="text-2xl font-black text-amber-900">{form.opening + form.purchased - form.closing} Liters</span>
          </div>
          <button onClick={handleFuelEntry} className="w-full py-4 bg-amber-600 text-white font-bold rounded-md hover:bg-amber-700 transition-colors uppercase">
            Record Fuel Consumption
          </button>
        </div>
      </div>

      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">Recent Logs</h3>
        <div className="overflow-x-auto">
          <table className="w-full text-left text-xs">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-4 py-2">Date</th>
                <th className="px-4 py-2">Shift</th>
                <th className="px-4 py-2">Used</th>
                <th className="px-4 py-2">Ratio</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.fuelLogs.slice(0, 10).map(log => (
                <tr key={log.id} className="hover:bg-slate-50">
                  <td className="px-4 py-3">{log.date}</td>
                  <td className="px-4 py-3 font-medium text-slate-600">{log.shift}</td>
                  <td className="px-4 py-3 font-bold text-slate-800">{log.used} L</td>
                  <td className="px-4 py-3 font-bold text-blue-600">
                    {log.totalProdWeightOnDate > 0 ? (log.used / log.totalProdWeightOnDate).toFixed(2) : 'N/A'} L/kg
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
