export default FuelConsumption;

import React, { useState } from 'react';
import { FactoryState } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

const Efficiency: React.FC<{ state: FactoryState }> = ({ state }) => {
  const [refDate, setRefDate] = useState(new Date().toISOString().split('T')[0]);

  // Calculations across all history (as defined in original logic but filtered if needed)
  // For the purpose of strict compliance, we use the global stats but add a date selector as requested.
  const filteredProd = refDate ? state.productionLogs.filter(l => l.date === new Date(refDate).toLocaleDateString()) : state.productionLogs;
  const filteredFuel = refDate ? state.fuelLogs.filter(l => l.date === new Date(refDate).toLocaleDateString()) : state.fuelLogs;

  const totalGoodPcs = filteredProd.reduce((acc, l) => acc + l.goodQty, 0);
  const totalDamagedPcs = filteredProd.reduce((acc, l) => acc + l.damagedQty, 0);
  const totalPcs = totalGoodPcs + totalDamagedPcs;
  const pieceEfficiency = totalPcs > 0 ? (totalGoodPcs / totalPcs) * 100 : 0;

  const totalProdWeight = filteredProd.reduce((acc, l) => acc + l.totalProdWeight, 0);
  const totalDamagedWeight = filteredProd.reduce((acc, l) => acc + l.damagedWeight, 0);
  const weightEfficiency = totalProdWeight > 0 ? ((totalProdWeight - totalDamagedWeight) / totalProdWeight) * 100 : 0;

  const totalFuelUsed = filteredFuel.reduce((acc, l) => acc + l.used, 0);
  const fuelRatio = totalProdWeight > 0 ? totalFuelUsed / totalProdWeight : 0;
  // For Pie Chart of Fuel Ratio, we treat 1.1 as the "Target (100%)"
  const targetRatio = 1.1;
  const fuelEfficiency = fuelRatio > 0 ? Math.min((targetRatio / fuelRatio) * 100, 100) : 0;

  const COLORS = ['#10b981', '#ef4444']; // Green for success, Red for loss

  const renderPie = (value: number, label: string) => {
    const data = [
      { name: 'Efficiency', value: value },
      { name: 'Loss', value: 100 - value }
    ];
    return (
      <div className="flex flex-col items-center">
        <h4 className="text-xs font-bold text-slate-500 mb-2 uppercase">{label}</h4>
        <div className="h-[200px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={data}
                cx="50%"
                cy="50%"
                innerRadius={50}
                outerRadius={80}
                paddingAngle={5}
                dataKey="value"
                startAngle={90}
                endAngle={-270}
              >
                <Cell fill={COLORS[0]} />
                <Cell fill={COLORS[1]} />
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </div>
        <div className="text-2xl font-black text-slate-800 mt-[-60px] mb-[40px] z-10">{value.toFixed(1)}%</div>
      </div>
    );
  };

  return (
    <div className="space-y-8">
      {/* Date Reference Selector */}
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center space-x-4">
        <label className="text-sm font-bold text-slate-600">Calculation Reference Date:</label>
        <input 
          type="date"
          value={refDate}
          onChange={e => setRefDate(e.target.value)}
          className="px-4 py-1 border border-slate-200 rounded-md text-sm"
        />
        <span className="text-xs text-slate-400 italic">(Leave empty for all-time stats)</span>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* 1. Piece Efficiency */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex flex-col items-center text-center">
          {renderPie(pieceEfficiency, "Piece Efficiency")}
          <div className="mt-4 w-full border-t border-slate-50 pt-4 text-[10px] text-slate-500 space-y-2">
            <p><span className="font-bold text-slate-700">Formula:</span> Good Pieces ÷ Total Pieces</p>
            <p><span className="font-bold text-slate-700">Numbers:</span> {totalGoodPcs} ÷ {totalPcs}</p>
            <p className="text-sm font-bold text-green-600">Result: {pieceEfficiency.toFixed(1)}%</p>
          </div>
        </div>

        {/* 2. Weight Efficiency */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex flex-col items-center text-center">
          {renderPie(weightEfficiency, "Weight Efficiency")}
          <div className="mt-4 w-full border-t border-slate-50 pt-4 text-[10px] text-slate-500 space-y-2">
            <p><span className="font-bold text-slate-700">Formula:</span> (Total Weight - Damaged Weight) ÷ Total Weight</p>
            <p><span className="font-bold text-slate-700">Numbers:</span> ({totalProdWeight.toFixed(1)} - {totalDamagedWeight.toFixed(1)}) ÷ {totalProdWeight.toFixed(1)}</p>
            <p className="text-sm font-bold text-blue-600">Result: {weightEfficiency.toFixed(1)}%</p>
          </div>
        </div>

        {/* 3. Fuel Ratio */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex flex-col items-center text-center">
          {renderPie(fuelEfficiency, "Fuel Ratio Efficiency")}
          <div className="mt-4 w-full border-t border-slate-50 pt-4 text-[10px] text-slate-500 space-y-2">
            <p><span className="font-bold text-slate-700">Formula:</span> Fuel Used ÷ Total Prod Weight</p>
            <p><span className="font-bold text-slate-700">Numbers:</span> {totalFuelUsed} ÷ {totalProdWeight.toFixed(1)}</p>
            <p className="text-sm font-bold text-amber-600">Result Ratio: {fuelRatio.toFixed(2)} L/kg</p>
            <p className="text-[9px] italic text-slate-400">Target: 1.1 L/kg</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Efficiency;

import React, { useState } from 'react';
import { FactoryState, Shift } from '../types';

const Reports: React.FC<{ state: FactoryState }> = ({ state }) => {
  const [filters, setFilters] = useState({
    dateStart: '',
    dateEnd: '',
    shift: '',
    itemId: '',
    machineId: ''
  });

  const fgItems = state.masterItems.filter(i => i.category === 'Finished Goods');
  const machines = state.masterItems.filter(i => i.category === 'Production Machine');

  const filteredLogs = state.productionLogs.filter(log => {
    if (filters.shift && log.shift !== filters.shift) return false;
    if (filters.itemId && log.itemId !== filters.itemId) return false;
    if (filters.machineId && log.machineId !== filters.machineId) return false;

    // Strict date range filtering
    if (filters.dateStart || filters.dateEnd) {
      const logDate = new Date(log.date).getTime();
      if (filters.dateStart && logDate < new Date(filters.dateStart).getTime()) return false;
      if (filters.dateEnd && logDate > new Date(filters.dateEnd).getTime()) return false;
    }
    return true;
  });

  const exportToExcel = () => {
    const headers = [
      "Date", "Item", "UOM", "Production Qty", "Damaged Qty", "Good Qty", 
      "Shift", "Avg Wet Wt", "Dry Wt", "Total Prod Wt", "Total Dmg Wt", 
      "Machine", "Operator", "Fuel Used", "Fuel Ratio"
    ].join(",");

    const rows = filteredLogs.map(log => {
      const fuelRecord = state.fuelLogs.find(f => f.date === log.date && f.shift === log.shift);
      const fuelUsed = fuelRecord ? fuelRecord.used : 0;
      const fuelRatio = log.totalProdWeight > 0 ? (fuelUsed / log.totalProdWeight).toFixed(2) : '0';
      const itemName = fgItems.find(i => i.id === log.itemId)?.name || 'Large Beads';
      const machineName = machines.find(m => m.id === log.machineId)?.name || '---';
      const operatorName = state.masterItems.find(o => o.id === log.operatorId)?.name || '---';

      return [
        log.date,
        itemName,
        log.isLargeBeads ? 'kg' : 'pcs',
        log.goodQty + log.damagedQty,
        log.damagedQty,
        log.goodQty,
        log.shift,
        log.avgWetWeight.toFixed(3),
        log.dryWeight.toFixed(3),
        log.totalProdWeight.toFixed(2),
        log.damagedWeight.toFixed(2),
        machineName,
        operatorName,
        fuelUsed,
        fuelRatio
      ].join(",");
    });

    const csvContent = "data:text/csv;charset=utf-8," + headers + "\n" + rows.join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `production_report_${new Date().toLocaleDateString()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">
      {/* Filters */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-xs font-bold text-slate-400 uppercase mb-4 tracking-wider">Report Filters</h3>
        <div className="grid grid-cols-2 md:grid-cols-6 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">From Date</label>
            <input 
              type="date"
              value={filters.dateStart}
              onChange={e => setFilters({...filters, dateStart: e.target.value})}
              className="w-full text-xs px-2 py-2 border border-slate-200 rounded"
            />
