                <th className="px-2 py-3 font-bold text-slate-500 whitespace-nowrap">Date</th>
                <th className="px-2 py-3 font-bold text-slate-500">Item</th>
                <th className="px-2 py-3 font-bold text-slate-500">UOM</th>
                <th className="px-2 py-3 font-bold text-slate-500">Prod Qty</th>
                <th className="px-2 py-3 font-bold text-slate-500">Dmg Qty</th>
                <th className="px-2 py-3 font-bold text-slate-500 text-green-700">Good Qty</th>
                <th className="px-2 py-3 font-bold text-slate-500">Shift</th>
                <th className="px-2 py-3 font-bold text-slate-500">Avg Wet</th>
                <th className="px-2 py-3 font-bold text-slate-500">Dry Wt</th>
                <th className="px-2 py-3 font-bold text-slate-500">Total Prod (kg)</th>
                <th className="px-2 py-3 font-bold text-slate-500">Total Dmg (kg)</th>
                <th className="px-2 py-3 font-bold text-slate-500">Machine</th>
                <th className="px-2 py-3 font-bold text-slate-500">Operator</th>
