          {editingId && <button onClick={() => {setEditingId(null); setForm({...form, totalQty: 0, damagedQty: 0, avgWetWeight: 0});}} className="px-8 py-4 bg-slate-200 text-slate-700 font-bold rounded-md hover:bg-slate-300 uppercase">Cancel</button>}
