import React, { useState } from 'react';
import { FactoryState, Shift, SiloType } from '../types';
import { createAuditLog } from '../store';
import { SHIFTS, MAX_SILO_CAPACITY } from '../constants';
import SiloGraphic from '../components/SiloGraphic';

const SiloManagement: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [openingValues, setOpeningValues] = useState<Record<number, number>>(Object.fromEntries(state.silos.map(s => [s.id, s.currentStock])));
  const [adjustment, setAdjustment] = useState({ siloId: 1, qty: 0, reason: '', date: new Date().toISOString().split('T')[0] });
  const [expanding, setExpanding] = useState({ shift: Shift.Day, operatorId: '', qty: 0, destId: 5, isLargeBeads: false, date: new Date().toISOString().split('T')[0] });
  const [editingExpId, setEditingExpId] = useState<string | null>(null);

  const operators = state.masterItems.filter(i => i.category === 'Operator');

  const handleSetOpening = () => {
    if (state.siloOpeningSet) return;
    updateState(prev => {
      const newSilos = prev.silos.map(s => ({ ...s, currentStock: openingValues[s.id] || 0 }));
      return { ...prev, silos: newSilos, siloOpeningSet: true, auditLogs: [createAuditLog('Silo Management', 'ADJUST', '0', 'Opening Silo Stock Set'), ...prev.auditLogs] };
    });
  };

  const handleAdjust = () => {
    if (adjustment.qty === 0 || !adjustment.date) return;
    updateState(prev => {
      const silo = prev.silos.find(s => s.id === adjustment.siloId);
      if (!silo) return prev;
      const newQty = silo.currentStock + adjustment.qty;
      if (newQty < 0 || newQty > MAX_SILO_CAPACITY) { alert('Invalid qty!'); return prev; }
      const formattedDate = new Date(adjustment.date).toLocaleDateString();
      const newSilos = prev.silos.map(s => s.id === adjustment.siloId ? { ...s, currentStock: newQty } : s);
      const auditLog = createAuditLog('Silo Management', 'ADJUST', silo.currentStock.toString(), `Manual Adjustment: ${adjustment.qty}kg on ${formattedDate}`);
      return { ...prev, silos: newSilos, auditLogs: [auditLog, ...prev.auditLogs] };
    });
    setAdjustment({ ...adjustment, qty: 0, reason: '' });
  };

  const handleSecondExpand = () => {
    if (expanding.qty <= 0 || !expanding.date) return;
    updateState(prev => {
      let newState = { ...prev };
      const formattedDate = new Date(expanding.date).toLocaleDateString();

      if (editingExpId) {
        const old = prev.secondExpandingLogs.find(l => l.id === editingExpId);
        if (old) {
          newState.silos = newState.silos.map(s => {
            if (s.id === 10) return { ...s, currentStock: s.currentStock + old.quantityKg };
            if (s.id === old.destSiloId) return { ...s, currentStock: s.currentStock - old.quantityKg };
            return s;
          });
          newState.secondExpandingLogs = newState.secondExpandingLogs.filter(l => l.id !== editingExpId);
        }
      }

      const silo10 = newState.silos.find(s => s.id === 10);
      const destSilo = newState.silos.find(s => s.id === expanding.destId);
      if (!silo10 || silo10.currentStock < expanding.qty || !destSilo || destSilo.currentStock + expanding.qty > MAX_SILO_CAPACITY) {
        alert('Validation failed (Insufficient stock or capacity)!'); return prev;
      }

      const entryId = editingExpId || crypto.randomUUID();
      newState.silos = newState.silos.map(s => {
        if (s.id === 10) return { ...s, currentStock: s.currentStock - expanding.qty };
        if (s.id === expanding.destId) return { ...s, currentStock: s.currentStock + expanding.qty, materialName: silo10.materialName };
        return s;
      });
      const newLog = { id: entryId, ...expanding, quantityKg: expanding.qty, destSiloId: expanding.destId, date: formattedDate };
      newState.secondExpandingLogs = [newLog, ...newState.secondExpandingLogs];
      newState.auditLogs = [createAuditLog('Silo Management', editingExpId ? 'UPDATE' : 'CREATE', '', `Exp: ${expanding.qty}kg S10 -> S${expanding.destId}`), ...newState.auditLogs];
      return newState;
    });
    setExpanding({ ...expanding, qty: 0 });
    setEditingExpId(null);
  };

  const deleteExpLog = (id: string) => {
    if (!confirm('Reverse stock?')) return;
    updateState(prev => {
      const entry = prev.secondExpandingLogs.find(l => l.id === id);
      if (!entry) return prev;
      const newSilos = prev.silos.map(s => {
        if (s.id === 10) return { ...s, currentStock: s.currentStock + entry.quantityKg };
        if (s.id === entry.destSiloId) return { ...s, currentStock: s.currentStock - entry.quantityKg };
        return s;
      });
      return { ...prev, silos: newSilos, secondExpandingLogs: prev.secondExpandingLogs.filter(l => l.id !== id), auditLogs: [createAuditLog('Silo Management', 'DELETE', id, 'Reversed Expansion'), ...prev.auditLogs] };
    });
  };

  return (
    <div className="space-y-8">
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm"><h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider">Silo Monitoring</h3><div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-7 gap-4">{state.silos.map(silo => (<SiloGraphic key={silo.id} silo={silo} />))}</div></div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm"><h3 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">Manual Adjustment</h3><div className="space-y-4"><div><label className="text-xs font-bold text-slate-500">Date</label><input type="date" value={adjustment.date} onChange={e => setAdjustment({...adjustment, date: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded-md" /></div><div><label className="text-xs font-bold text-slate-500">Silo</label><select value={adjustment.siloId} onChange={e => setAdjustment({...adjustment, siloId: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded-md">{state.silos.map(s => <option key={s.id} value={s.id}>Silo {s.id}</option>)}</select></div><div><label className="text-xs font-bold text-slate-500">Qty (+/- kg)</label><input type="number" value={adjustment.qty} onChange={e => setAdjustment({...adjustment, qty: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded-md" /></div><button onClick={handleAdjust} className="w-full py-2 bg-slate-700 text-white font-bold rounded-md">Adjust Stock</button></div></div>
        <div className="bg-blue-50 p-6 rounded-xl border border-blue-200 shadow-sm"><h3 className="text-sm font-bold text-blue-900 mb-4 uppercase tracking-wider">Second Expanding</h3><div className="space-y-4"><div><label className="text-xs font-bold text-slate-500">Date</label><input type="date" value={expanding.date} onChange={e => setExpanding({...expanding, date: e.target.value})} className="w-full px-4 py-2 border border-blue-200 rounded-md" /></div><div className="grid grid-cols-2 gap-4"><div><label className="text-xs font-bold text-slate-500">Dest</label><select value={expanding.destId} onChange={e => setExpanding({...expanding, destId: Number(e.target.value)})} className="w-full px-4 py-2 border border-blue-200 rounded-md"><option value={5}>Silo 5</option><option value={7}>Silo 7</option></select></div><div><label className="text-xs font-bold text-slate-500">Qty (kg)</label><input type="number" value={expanding.qty} onChange={e => setExpanding({...expanding, qty: Number(e.target.value)})} className="w-full px-4 py-2 border border-blue-200 rounded-md" /></div></div><button onClick={handleSecondExpand} className="w-full py-3 bg-blue-600 text-white font-bold rounded-md uppercase">{editingExpId ? 'Update' : 'Process'}</button>{editingExpId && <button onClick={() => setEditingExpId(null)} className="w-full text-xs text-slate-400 mt-1">Cancel Edit</button>}</div></div>
      </div>
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm"><h3 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">Expansion History</h3><div className="overflow-x-auto"><table className="w-full text-left text-xs"><thead className="bg-slate-50"><tr><th className="px-4 py-3">Date</th><th className="px-4 py-3">Source</th><th className="px-4 py-3">Dest</th><th className="px-4 py-3">Qty</th><th className="px-4 py-3 text-right">Actions</th></tr></thead><tbody className="divide-y divide-slate-100">{state.secondExpandingLogs.map(log => (<tr key={log.id} className="hover:bg-slate-50"><td className="px-4 py-3">{log.date}</td><td className="px-4 py-3">Silo 10</td><td className="px-4 py-3">Silo {log.destSiloId}</td><td className="px-4 py-3 font-bold">{log.quantityKg} kg</td><td className="px-4 py-3 text-right space-x-2"><button onClick={() => {setEditingExpId(log.id); setExpanding({shift: log.shift, operatorId: log.operatorId, qty: log.quantityKg, destId: log.destSiloId, isLargeBeads: log.isLargeBeads, date: new Date(log.date).toISOString().split('T')[0]});}} className="text-blue-600 font-bold">Edit</button><button onClick={() => deleteExpLog(log.id)} className="text-red-600 font-bold">Delete</button></td></tr>))}</tbody></table></div></div>
    </div>
  );
};

export default SiloManagement;

import React, { useState } from 'react';
import { FactoryState } from '../types';
import { createAuditLog } from '../store';

const FinishedGoods: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [openingValues, setOpeningValues] = useState<Record<string, { pcs: number; weight: number }>>({});
  const [adjustment, setAdjustment] = useState({ itemId: '', qty: 0, reason: '', date: new Date().toISOString().split('T')[0] });

  const fgItems = state.masterItems.filter(i => i.category === 'Finished Goods');
  const hasProductionRecords = state.productionLogs.length > 0;

  const handleSetOpening = () => {
    if (state.fgOpeningSet || hasProductionRecords) return;
    const values = Object.values(openingValues) as { pcs: number; weight: number }[];
    if (values.some(v => v.pcs < 0 || v.weight < 0)) { alert('Values cannot be negative.'); return; }

    updateState(prev => {
      const newFgStock = prev.fgStock.map(s => {
        const ov = openingValues[s.itemId];
        if (ov) return { ...s, stockPieces: ov.pcs, totalWeight: ov.weight };
        return s;
      });
      return { ...prev, fgStock: newFgStock, fgOpeningSet: true, auditLogs: [createAuditLog('Finished Goods', 'ADJUST', '0', 'Opening stock set'), ...prev.auditLogs] };
    });
  };

  const handleAdjust = () => {
    if (!adjustment.itemId || adjustment.qty === 0 || !adjustment.date) return;
    updateState(prev => {
      const stock = prev.fgStock.find(s => s.itemId === adjustment.itemId);
      if (!stock || stock.stockPieces + adjustment.qty < 0) { alert('Invalid qty!'); return prev; }
      const formattedDate = new Date(adjustment.date).toLocaleDateString();
      const newFgStock = prev.fgStock.map(s => s.itemId === adjustment.itemId ? { ...s, stockPieces: s.stockPieces + adjustment.qty } : s);
      const logMsg = `Adjustment Log: ${adjustment.qty} pcs of ${fgItems.find(i => i.id === adjustment.itemId)?.name} on ${formattedDate}`;
      return { ...prev, fgStock: newFgStock, auditLogs: [createAuditLog('Finished Goods', 'ADJUST', stock.stockPieces.toString(), logMsg), ...prev.auditLogs] };
    });
    setAdjustment({ ...adjustment, qty: 0, reason: '' });
  };

  return (
    <div className="space-y-8">
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm"><h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider">Inventory Status</h3><div className="grid grid-cols-1 md:grid-cols-4 gap-6">{state.fgStock.map(s => (<div key={s.itemId} className="p-4 bg-slate-50 border border-slate-100 rounded-lg"><div className="text-xs font-bold text-slate-400 uppercase">{fgItems.find(i => i.id === s.itemId)?.name}</div><div className="text-2xl font-extrabold text-slate-900">{s.stockPieces.toLocaleString()} Pcs</div></div>))}</div></div>
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm"><h3 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">Manual Adjustment</h3><div className="space-y-4"><div><label className="text-xs font-bold text-slate-500">Date</label><input type="date" value={adjustment.date} onChange={e => setAdjustment({...adjustment, date: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded" /></div><div><label className="text-xs font-bold text-slate-500">Item</label><select value={adjustment.itemId} onChange={e => setAdjustment({...adjustment, itemId: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded"><option value="">-- Select --</option>{fgItems.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}</select></div><div><label className="text-xs font-bold text-slate-500">Qty (+ / - Pcs)</label><input type="number" value={adjustment.qty} onChange={e => setAdjustment({...adjustment, qty: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" /></div><button onClick={handleAdjust} className="w-full py-2 bg-slate-800 text-white font-bold rounded">Apply Adjustment</button></div></div>
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm overflow-hidden"><h3 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">Audit Logs</h3><div className="text-[10px] overflow-y-auto h-[200px]"><table className="w-full text-left"><thead><tr><th className="py-2">Time</th><th className="py-2">Detail</th></tr></thead><tbody className="divide-y divide-slate-50">{state.auditLogs.filter(l => l.module === 'Finished Goods').map(l => (<tr key={l.id}><td>{l.date} {l.time}</td><td>{l.newValue}</td></tr>))}</tbody></table></div></div>
      </div>
    </div>
  );
};

export default FinishedGoods;

import React, { useState } from 'react';
import { FactoryState, Shift, FuelEntry } from '../types';
import { createAuditLog } from '../store';
import { SHIFTS } from '../constants';

const FuelConsumption: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState({
    date: new Date().toISOString().split('T')[0],
    shift: Shift.Day,
    opening: 0,
    purchased: 0,
    closing: 0
  });

  const handleFuelEntry = () => {
    const used = form.opening + form.purchased - form.closing;
    if (used < 0 || !form.date) { alert('Invalid calculation or missing date!'); return; }

    const formattedDate = new Date(form.date).toLocaleDateString();
    const todaysProd = state.productionLogs.filter(l => l.date === formattedDate).reduce((acc, l) => acc + l.totalProdWeight, 0);

    updateState(prev => {
      const entry: FuelEntry = { id: editingId || crypto.randomUUID(), ...form, date: formattedDate, used, totalProdWeightOnDate: todaysProd };
      let newLogs = prev.fuelLogs;
      if (editingId) newLogs = newLogs.filter(l => l.id !== editingId);
      const auditLog = createAuditLog('Fuel Consumption', editingId ? 'UPDATE' : 'CREATE', '', `Entry: ${used}L used on ${formattedDate}`);
      return { ...prev, fuelLogs: [entry, ...newLogs], auditLogs: [auditLog, ...prev.auditLogs] };
    });
    setForm({ ...form, purchased: 0 });
    setEditingId(null);
  };

  const handleDelete = (id: string) => {
    if (!confirm('Delete record?')) return;
    updateState(prev => {
      const auditLog = createAuditLog('Fuel Consumption', 'DELETE', id, 'Deleted record.');
      return { ...prev, fuelLogs: prev.fuelLogs.filter(l => l.id !== id), auditLogs: [auditLog, ...prev.auditLogs] };
    });
  };

  const handleEdit = (log: FuelEntry) => {
    setEditingId(log.id);
    const dateParts = log.date.split('/');
    const isoDate = dateParts.length === 3 ? `${dateParts[2]}-${dateParts[0].padStart(2, '0')}-${dateParts[1].padStart(2, '0')}` : new Date().toISOString().split('T')[0];
    setForm({ date: isoDate, shift: log.shift, opening: log.opening, purchased: log.purchased, closing: log.closing });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="space-y-8">
      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider">{editingId ? 'Edit' : 'New'} Consumption Entry</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
          <div><label className="text-xs font-bold text-slate-500">Date</label><input type="date" value={form.date} onChange={e => setForm({...form, date: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded" /></div>
          <div><label className="text-xs font-bold text-slate-500">Shift</label><select value={form.shift} onChange={e => setForm({...form, shift: e.target.value as Shift})} className="w-full px-4 py-2 border border-slate-300 rounded">{SHIFTS.map(s => <option key={s} value={s}>{s}</option>)}</select></div>
          <div><label className="text-xs font-bold text-slate-500">Opening (L)</label><input type="number" value={form.opening} onChange={e => setForm({...form, opening: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" /></div>
          <div><label className="text-xs font-bold text-slate-500">Purchased (L)</label><input type="number" value={form.purchased} onChange={e => setForm({...form, purchased: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" /></div>
          <div><label className="text-xs font-bold text-slate-500">Closing (L)</label><input type="number" value={form.closing} onChange={e => setForm({...form, closing: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" /></div>
        </div>
        <div className="mt-6 flex space-x-4"><button onClick={handleFuelEntry} className="flex-1 py-4 bg-amber-600 text-white font-bold rounded-md uppercase">{editingId ? 'Update' : 'Record'} Consumption</button>{editingId && <button onClick={() => setEditingId(null)} className="px-8 bg-slate-200 font-bold rounded-md">Cancel</button>}</div>
      </div>

      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">Fuel Consumption Logs</h3>
        <div className="overflow-x-auto"><table className="w-full text-left text-xs"><thead className="bg-slate-50"><tr><th className="px-4 py-2">Date</th><th className="px-4 py-2">Shift</th><th className="px-4 py-2">Used</th><th className="px-4 py-2 text-right">Actions</th></tr></thead><tbody className="divide-y divide-slate-100">{state.fuelLogs.map(log => (<tr key={log.id} className="hover:bg-slate-50"><td className="px-4 py-2">{log.date}</td><td className="px-4 py-2">{log.shift}</td><td className="px-4 py-2 font-bold">{log.used} L</td><td className="px-4 py-2 text-right space-x-2"><button onClick={() => handleEdit(log)} className="text-blue-600 font-bold">Edit</button><button onClick={() => handleDelete(log.id)} className="text-red-600 font-bold">Delete</button></td></tr>))}</tbody></table></div>
      </div>
    </div>
  );
};

export default FuelConsumption;

import React, { useState } from 'react';
import { FactoryState } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

const Efficiency: React.FC<{ state: FactoryState }> = ({ state }) => {
  const [refDate, setRefDate] = useState(new Date().toISOString().split('T')[0]);

  const filteredProd = refDate ? state.productionLogs.filter(l => l.date === new Date(refDate).toLocaleDateString()) : state.productionLogs;
  const filteredFuel = refDate ? state.fuelLogs.filter(l => l.date === new Date(refDate).toLocaleDateString()) : state.fuelLogs;

  const totalGoodPcs = filteredProd.reduce((acc, l) => acc + l.goodQty, 0);
  const totalDamagedPcs = filteredProd.reduce((acc, l) => acc + l.damagedQty, 0);
  const totalPcs = totalGoodPcs + totalDamagedPcs;
  const pieceEfficiency = totalPcs > 0 ? (totalGoodPcs / totalPcs) * 100 : 0;

  const totalProdWeight = filteredProd.reduce((acc, l) => acc + l.totalProdWeight, 0);
  const totalDamagedWeight = filteredProd.reduce((acc, l) => acc + l.damagedWeight, 0);
  const weightEfficiency = totalProdWeight > 0 ? ((totalProdWeight - totalDamagedWeight) / totalProdWeight) * 100 : 0;

  const totalFuelUsed = filteredFuel.reduce((acc, l) => acc + l.used, 0);
  const fuelRatio = totalProdWeight > 0 ? totalFuelUsed / totalProdWeight : 0;
  const targetRatio = 1.1;
  const fuelEfficiency = fuelRatio > 0 ? Math.min((targetRatio / fuelRatio) * 100, 100) : 0;

  const COLORS = ['#10b981', '#ef4444'];

  const renderEfficiencyCard = (value: number, label: string, formula: string, actuals: string, finalResult: string) => {
    const data = [{ name: 'Efficiency', value: value }, { name: 'Loss', value: 100 - value }];
    return (
      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm flex flex-col items-center">
        <h4 className="text-xs font-bold text-slate-500 mb-6 uppercase tracking-widest">{label}</h4>
        <div className="w-full h-[320px] relative">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie data={data} cx="50%" cy="50%" innerRadius={80} outerRadius={120} paddingAngle={5} dataKey="value" startAngle={90} endAngle={-270}>
                <Cell fill={COLORS[0]} />
                <Cell fill={COLORS[1]} />
              </Pie>
              <Tooltip />
              <Legend verticalAlign="bottom" height={36}/>
            </PieChart>
          </ResponsiveContainer>
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <span className="text-3xl font-black text-slate-800">{value.toFixed(1)}%</span>
          </div>
        </div>
        <div className="mt-8 w-full border-t border-slate-50 pt-6 text-center space-y-3">
          <div className="text-[10px] text-slate-400 font-bold uppercase">Formula</div>
          <div className="text-xs font-medium text-slate-600">{formula}</div>
          <div className="text-[10px] text-slate-400 font-bold uppercase">Actual Numbers</div>
          <div className="text-sm font-bold text-slate-800">{actuals}</div>
          <div className="pt-2 text-lg font-black text-blue-600">{finalResult}</div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8">
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center space-x-4">
        <label className="text-sm font-bold text-slate-600">Reference Date:</label>
        <input type="date" value={refDate} onChange={e => setRefDate(e.target.value)} className="px-4 py-1 border border-slate-200 rounded-md text-sm" />
      </div>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {renderEfficiencyCard(pieceEfficiency, "Piece Efficiency", "Good Pieces / Total Pieces", `${totalGoodPcs} / ${totalPcs}`, `${pieceEfficiency.toFixed(1)}%`)}
        {renderEfficiencyCard(weightEfficiency, "Weight Efficiency", "(Total Weight - Dmg Weight) / Total Weight", `(${totalProdWeight.toFixed(1)} - ${totalDamagedWeight.toFixed(1)}) / ${totalProdWeight.toFixed(1)}`, `${weightEfficiency.toFixed(1)}%`)}
        {renderEfficiencyCard(fuelEfficiency, "Fuel Ratio", "Target Ratio / Actual Ratio", `1.1 / ${fuelRatio.toFixed(2)}`, `${fuelRatio.toFixed(2)} L/kg`)}
      </div>
    </div>
  );
};

export default Efficiency;

import React, { useState } from 'react';
import { FactoryState, Shift, ProductionEntry } from '../types';
import { createAuditLog } from '../store';
import { SHIFTS, DRY_WEIGHT_RATIO } from '../constants';

const Production: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState({
    date: new Date().toISOString().split('T')[0],
    shift: Shift.Day,
    machineId: '',
    operatorId: '',
    siloId: 5,
    itemId: '',
    totalQty: 0,
    damagedQty: 0,
    avgWetWeight: 0,
    isLargeBeads: false
  });

  const fgItems = state.masterItems.filter(i => i.category === 'Finished Goods');
  const operators = state.masterItems.filter(i => i.category === 'Operator');
  const machines = state.masterItems.filter(i => i.category === 'Production Machine');

  // Auto-calculated good quantity for Finished Goods
  const goodQty = form.isLargeBeads ? 0 : Math.max(0, form.totalQty - form.damagedQty);

  const handleProduction = () => {
    if (!form.operatorId || !form.machineId || !form.itemId || !form.date) {
      alert('Required fields missing, including date!');
      return;
    }
    if (form.totalQty <= 0) {
      alert(form.isLargeBeads ? 'Total Quantity (kg) must be greater than zero.' : 'Total Quantity (Pieces) must be greater than zero.');
      return;
    }

    if (!form.isLargeBeads && form.damagedQty > form.totalQty) {
      alert('Damaged Quantity cannot exceed Total Quantity.');
      return;
    }

    let dryWeight = 0;
    let totalProdWeight = 0;
    let damagedWeight = 0;

    if (form.isLargeBeads) {
      // B. LARGE EXPANDING BEADS (Kg)
      totalProdWeight = form.totalQty;
      damagedWeight = 0;
      dryWeight = 0; // Not applicable
    } else {
      // A. FINISHED GOODS (Pieces)
      dryWeight = form.avgWetWeight * DRY_WEIGHT_RATIO;
      totalProdWeight = form.totalQty * dryWeight;
      damagedWeight = form.damagedQty * dryWeight;
    }

    const silo = state.silos.find(s => s.id === form.siloId);
    if (!silo || silo.currentStock < totalProdWeight) {
      alert(`Insufficient stock in Silo ${form.siloId}! Needs ${totalProdWeight.toFixed(2)}kg`);
      return;
    }

    updateState(prev => {
      let newState = { ...prev };

      // If editing, reverse the previous entry's stock changes
      if (editingId) {
        const oldEntry = prev.productionLogs.find(l => l.id === editingId);
        if (oldEntry) {
          newState.silos = newState.silos.map(s => s.id === oldEntry.siloId ? { ...s, currentStock: s.currentStock + oldEntry.totalProdWeight } : s);
          if (!oldEntry.isLargeBeads) {
            newState.fgStock = newState.fgStock.map(s => s.itemId === oldEntry.itemId ? { ...s, stockPieces: s.stockPieces - oldEntry.goodQty, totalWeight: s.totalWeight - (oldEntry.goodQty * oldEntry.dryWeight) } : s);
          }
          newState.productionLogs = newState.productionLogs.filter(l => l.id !== editingId);
        }
      }

      const formattedDate = new Date(form.date).toLocaleDateString();
      const entry: ProductionEntry = {
        id: editingId || crypto.randomUUID(),
        ...form,
        date: formattedDate,
        goodQty,
        dryWeight,
        totalProdWeight,
        damagedWeight
      };

      // Apply new stock changes
      newState.silos = newState.silos.map(s => s.id === form.siloId ? { ...s, currentStock: s.currentStock - totalProdWeight } : s);
      if (!form.isLargeBeads) {
        newState.fgStock = newState.fgStock.map(s => s.itemId === form.itemId ? { ...s, stockPieces: s.stockPieces + goodQty, totalWeight: s.totalWeight + (goodQty * dryWeight) } : s);
      }

      const logMsg = `${editingId ? 'Updated' : 'Recorded'} Production: ${form.totalQty} ${form.isLargeBeads ? 'kg' : 'pcs'} on ${formattedDate}`;
      const auditLog = createAuditLog('Production', editingId ? 'UPDATE' : 'CREATE', '', logMsg);

      return {
        ...newState,
        productionLogs: [entry, ...newState.productionLogs],
        auditLogs: [auditLog, ...newState.auditLogs]
      };
    });

    // Reset relevant fields
    setForm({ ...form, totalQty: 0, damagedQty: 0, avgWetWeight: 0 });
    setEditingId(null);
  };

  const handleDelete = (id: string) => {
    if (!confirm('Are you sure you want to delete this record? Stock will be reversed.')) return;
    updateState(prev => {
      const entry = prev.productionLogs.find(l => l.id === id);
      if (!entry) return prev;

      const newSilos = prev.silos.map(s => s.id === entry.siloId ? { ...s, currentStock: s.currentStock + entry.totalProdWeight } : s);
      let newFgStock = [...prev.fgStock];
      if (!entry.isLargeBeads) {
        newFgStock = prev.fgStock.map(s => s.itemId === entry.itemId ? { ...s, stockPieces: s.stockPieces - entry.goodQty, totalWeight: s.totalWeight - (entry.goodQty * entry.dryWeight) } : s);
      }

      const auditLog = createAuditLog('Production', 'DELETE', `ID: ${id}`, 'Deleted record and reversed stock.');

      return {
        ...prev,
        productionLogs: prev.productionLogs.filter(l => l.id !== id),
        silos: newSilos,
        fgStock: newFgStock,
        auditLogs: [auditLog, ...prev.auditLogs]
      };
    });
  };

  const handleEdit = (entry: ProductionEntry) => {
    setEditingId(entry.id);
    const dateParts = entry.date.split('/');
    const isoDate = dateParts.length === 3 ? `${dateParts[2]}-${dateParts[0].padStart(2, '0')}-${dateParts[1].padStart(2, '0')}` : new Date().toISOString().split('T')[0];
    setForm({
      date: isoDate,
      shift: entry.shift,
      machineId: entry.machineId,
      operatorId: entry.operatorId,
      siloId: entry.siloId,
      itemId: entry.itemId,
      totalQty: entry.totalQty,
      damagedQty: entry.damagedQty,
      avgWetWeight: entry.avgWetWeight,
      isLargeBeads: entry.isLargeBeads
    });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="space-y-8">
      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider">{editingId ? 'Edit' : 'New'} Production Entry</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Production Date</label>
            <input type="date" required value={form.date} onChange={e => setForm({ ...form, date: e.target.value })} className="w-full px-4 py-2 border border-slate-300 rounded-md" />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Shift</label>
            <select value={form.shift} onChange={e => setForm({...form, shift: e.target.value as Shift})} className="w-full px-4 py-2 border border-slate-300 rounded">
              {SHIFTS.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Machine</label>
            <select value={form.machineId} onChange={e => setForm({...form, machineId: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded">
              <option value="">-- Select --</option>
              {machines.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Operator</label>
            <select value={form.operatorId} onChange={e => setForm({...form, operatorId: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded">
              <option value="">-- Select --</option>
              {operators.map(o => <option key={o.id} value={o.id}>{o.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Source Silo</label>
            <select value={form.siloId} onChange={e => setForm({...form, siloId: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded">
              {state.silos.filter(s => s.id !== 10).map(s => <option key={s.id} value={s.id}>Silo {s.id} ({s.currentStock}kg)</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Production Type</label>
            <div className="flex items-center space-x-4 h-[42px]">
              <label className="flex items-center space-x-2 text-sm font-medium">
                <input type="radio" checked={!form.isLargeBeads} onChange={() => setForm({...form, isLargeBeads: false, totalQty: 0, damagedQty: 0, avgWetWeight: 0})} />
                <span>Finished Goods (Pieces)</span>
              </label>
              <label className="flex items-center space-x-2 text-sm font-medium">
                <input type="radio" checked={form.isLargeBeads} onChange={() => setForm({...form, isLargeBeads: true, totalQty: 0, damagedQty: 0, avgWetWeight: 0})} />
                <span>Large Expanding Beads (kg)</span>
              </label>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 border-t border-slate-100 pt-8">
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Item Selection</label>
            <select value={form.itemId} onChange={e => setForm({...form, itemId: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded">
              <option value="">-- Select Item --</option>
              {fgItems.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">
              {form.isLargeBeads ? 'Total Quantity (kg)' : 'Total Quantity (Pieces)'}
            </label>
            <input type="number" value={form.totalQty} onChange={e => setForm({...form, totalQty: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" />
          </div>
          {!form.isLargeBeads && (
            <>
              <div>
                <label className="block text-xs font-bold text-slate-500 mb-1">Damaged Quantity (Pieces)</label>
                <input type="number" value={form.damagedQty} onChange={e => setForm({...form, damagedQty: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 mb-1">Avg Wet Weight (kg/pc)</label>
                <input type="number" step="0.001" value={form.avgWetWeight} onChange={e => setForm({...form, avgWetWeight: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded" />
              </div>
            </>
          )}
        </div>

        <div className="mt-4 p-4 bg-slate-50 rounded-lg flex flex-wrap gap-8">
          {!form.isLargeBeads && (
            <>
              <div><span className="text-xs text-slate-500 font-bold uppercase">Good Quantity:</span><span className="ml-2 text-sm font-bold text-green-600">{goodQty} Pcs</span></div>
              {form.avgWetWeight > 0 && (
                <>
                  <div><span className="text-xs text-slate-500 font-bold uppercase">Dry Weight (Wet x 94%):</span><span className="ml-2 text-sm font-bold text-blue-600">{(form.avgWetWeight * DRY_WEIGHT_RATIO).toFixed(3)} kg</span></div>
                  <div><span className="text-xs text-slate-500 font-bold uppercase">Total Prod Weight:</span><span className="ml-2 text-sm font-bold text-blue-600">{(form.totalQty * (form.avgWetWeight * DRY_WEIGHT_RATIO)).toFixed(2)} kg</span></div>
                </>
              )}
            </>
          )}
          {form.isLargeBeads && form.totalQty > 0 && (
            <div><span className="text-xs text-slate-500 font-bold uppercase">Total Production Weight:</span><span className="ml-2 text-sm font-bold text-blue-600">{form.totalQty.toFixed(2)} kg</span></div>
          )}
        </div>

        <div className="mt-8 flex space-x-4">
          <button onClick={handleProduction} className="flex-1 py-4 bg-slate-900 text-white font-bold rounded-md hover:bg-black uppercase">
            {editingId ? 'Update Record' : 'Record Production Entry'}
          </button>
          {editingId && (
            <button 
              onClick={() => {
                setEditingId(null); 
                setForm({...form, totalQty: 0, damagedQty: 0, avgWetWeight: 0});
              }} 
              className="px-8 py-4 bg-slate-200 text-slate-700 font-bold rounded-md hover:bg-slate-300 uppercase"
            >
              Cancel
            </button>
          )}
        </div>
      </div>

      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">Production Records</h3>
        <div className="overflow-x-auto">
          <table className="w-full text-left text-xs">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-4 py-3">Date</th>
                <th className="px-4 py-3">Item</th>
                <th className="px-4 py-3">Machine</th>
                <th className="px-4 py-3">Type</th>
                <th className="px-4 py-3">Total Qty</th>
                <th className="px-4 py-3">Good/Dmg</th>
                <th className="px-4 py-3">Weight (kg)</th>
                <th className="px-4 py-3 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.productionLogs.map(log => {
                const item = fgItems.find(i => i.id === log.itemId);
                return (
                  <tr key={log.id} className="hover:bg-slate-50">
                    <td className="px-4 py-3">{log.date}</td>
                    <td className="px-4 py-3 font-medium">{item?.name}</td>
                    <td className="px-4 py-3">{machines.find(m => m.id === log.machineId)?.name}</td>
                    <td className="px-4 py-3">
                      <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${log.isLargeBeads ? 'bg-amber-100 text-amber-700' : 'bg-blue-100 text-blue-700'}`}>
                        {log.isLargeBeads ? 'Large Beads' : 'Finished Goods'}
                      </span>
                    </td>
                    <td className="px-4 py-3">{log.totalQty} {log.isLargeBeads ? 'kg' : 'pcs'}</td>
                    <td className="px-4 py-3">
                      {log.isLargeBeads ? '-' : `${log.goodQty} / ${log.damagedQty}`}
                    </td>
                    <td className="px-4 py-3 font-bold">{log.totalProdWeight.toFixed(2)}</td>
                    <td className="px-4 py-3 text-right space-x-3">
                      <button onClick={() => handleEdit(log)} className="text-blue-600 hover:text-blue-800 font-bold">Edit</button>
                      <button onClick={() => handleDelete(log.id)} className="text-red-600 hover:text-red-800 font-bold">Delete</button>
                    </td>
                  </tr>
                );
              })}
              {state.productionLogs.length === 0 && (
                <tr>
                  <td colSpan={8} className="px-4 py-8 text-center text-slate-400 italic">No production records found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Production;

import React, { useState } from 'react';
import { FactoryState } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

const Efficiency: React.FC<{ state: FactoryState }> = ({ state }) => {
  const [refDate, setRefDate] = useState(new Date().toISOString().split('T')[0]);

  const filteredProd = refDate ? state.productionLogs.filter(l => l.date === new Date(refDate).toLocaleDateString()) : state.productionLogs;
  const filteredFuel = refDate ? state.fuelLogs.filter(l => l.date === new Date(refDate).toLocaleDateString()) : state.fuelLogs;

  // PIECE EFFICIENCY: Exclude Large Expanding Beads
  const pieceProd = filteredProd.filter(l => !l.isLargeBeads);
  const totalGoodPcs = pieceProd.reduce((acc, l) => acc + l.goodQty, 0);
  const totalDamagedPcs = pieceProd.reduce((acc, l) => acc + l.damagedQty, 0);
  const totalPcs = totalGoodPcs + totalDamagedPcs;
  const pieceEfficiency = totalPcs > 0 ? (totalGoodPcs / totalPcs) * 100 : 0;

  // WEIGHT EFFICIENCY: Include everything
  const totalProdWeight = filteredProd.reduce((acc, l) => acc + l.totalProdWeight, 0);
  const totalDamagedWeight = filteredProd.reduce((acc, l) => acc + l.damagedWeight, 0);
  const weightEfficiency = totalProdWeight > 0 ? ((totalProdWeight - totalDamagedWeight) / totalProdWeight) * 100 : 0;

  // FUEL RATIO: Include everything
  const totalFuelUsed = filteredFuel.reduce((acc, l) => acc + l.used, 0);
  const fuelRatio = totalProdWeight > 0 ? totalFuelUsed / totalProdWeight : 0;
  const targetRatio = 1.1;
  const fuelEfficiency = fuelRatio > 0 ? Math.min((targetRatio / fuelRatio) * 100, 100) : 0;

  const COLORS = ['#10b981', '#ef4444'];

  const renderEfficiencyCard = (value: number, label: string, formula: string, actuals: string, finalResult: string) => {
    const data = [{ name: 'Efficiency', value: value }, { name: 'Loss', value: 100 - value }];
    return (
      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm flex flex-col items-center">
        <h4 className="text-xs font-bold text-slate-500 mb-6 uppercase tracking-widest">{label}</h4>
        <div className="w-full h-[320px] relative">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie data={data} cx="50%" cy="50%" innerRadius={80} outerRadius={120} paddingAngle={5} dataKey="value" startAngle={90} endAngle={-270}>
                <Cell fill={COLORS[0]} />
                <Cell fill={COLORS[1]} />
              </Pie>
              <Tooltip />
              <Legend verticalAlign="bottom" height={36}/>
            </PieChart>
          </ResponsiveContainer>
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <span className="text-3xl font-black text-slate-800">{value.toFixed(1)}%</span>
          </div>
        </div>
        <div className="mt-8 w-full border-t border-slate-50 pt-6 text-center space-y-3">
          <div className="text-[10px] text-slate-400 font-bold uppercase">Formula</div>
          <div className="text-xs font-medium text-slate-600">{formula}</div>
          <div className="text-[10px] text-slate-400 font-bold uppercase">Actual Numbers</div>
          <div className="text-sm font-bold text-slate-800">{actuals}</div>
          <div className="pt-2 text-lg font-black text-blue-600">{finalResult}</div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8">
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center space-x-4">
        <label className="text-sm font-bold text-slate-600">Reference Date:</label>
        <input type="date" value={refDate} onChange={e => setRefDate(e.target.value)} className="px-4 py-1 border border-slate-200 rounded-md text-sm" />
      </div>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {renderEfficiencyCard(pieceEfficiency, "Piece Efficiency", "Good Pieces / Total Pieces", `${totalGoodPcs} / ${totalPcs}`, `${pieceEfficiency.toFixed(1)}%`)}
        {renderEfficiencyCard(weightEfficiency, "Weight Efficiency", "(Total Weight - Dmg Weight) / Total Weight", `(${totalProdWeight.toFixed(1)} - ${totalDamagedWeight.toFixed(1)}) / ${totalProdWeight.toFixed(1)}`, `${weightEfficiency.toFixed(1)}%`)}
        {renderEfficiencyCard(fuelEfficiency, "Fuel Ratio", "Target Ratio / Actual Ratio", `1.1 / ${fuelRatio.toFixed(2)}`, `${fuelRatio.toFixed(2)} L/kg`)}
      </div>
      <p className="text-[10px] text-slate-400 italic text-center">* Note: Piece Efficiency excludes Large Expanding Beads (kg).</p>
    </div>
  );
};

export default Efficiency;

import React, { useState } from 'react';
import { FactoryState, Shift } from '../types';

const Reports: React.FC<{ state: FactoryState }> = ({ state }) => {
  const [filters, setFilters] = useState({
    dateStart: '',
    dateEnd: '',
    shift: '',
    itemId: '',
    machineId: ''
  });

  const fgItems = state.masterItems.filter(i => i.category === 'Finished Goods');
  const machines = state.masterItems.filter(i => i.category === 'Production Machine');

  const filteredLogs = state.productionLogs.filter(log => {
    if (filters.shift && log.shift !== filters.shift) return false;
    if (filters.itemId && log.itemId !== filters.itemId) return false;
    if (filters.machineId && log.machineId !== filters.machineId) return false;

    // Strict date range filtering
    if (filters.dateStart || filters.dateEnd) {
      const logDate = new Date(log.date).getTime();
      if (filters.dateStart && logDate < new Date(filters.dateStart).getTime()) return false;
      if (filters.dateEnd && logDate > new Date(filters.dateEnd).getTime()) return false;
    }
    return true;
  });

  const exportToExcel = () => {
    const headers = [
      "Date", "Item", "UOM", "Production Qty", "Damaged Qty", "Good Qty", 
      "Shift", "Average Wet Weight", "Dry Weight", "Total Production Weight", "Total Damaged Weight", 
      "Machine", "Operator", "Fuel Used", "Fuel Ratio"
    ].join(",");

    const rows = filteredLogs.map(log => {
      const fuelRecord = state.fuelLogs.find(f => f.date === log.date && f.shift === log.shift);
      const fuelUsed = fuelRecord ? fuelRecord.used : 0;
      const fuelRatio = log.totalProdWeight > 0 ? (fuelUsed / log.totalProdWeight).toFixed(2) : '0';
      const item = fgItems.find(i => i.id === log.itemId);
      const itemName = item?.name || (log.isLargeBeads ? 'Large Beads' : 'Unknown');
      const machineName = machines.find(m => m.id === log.machineId)?.name || '---';
      const operatorName = state.masterItems.find(o => o.id === log.operatorId)?.name || '---';

      return [
        log.date,
        itemName,
        log.isLargeBeads ? 'kg' : 'pcs',
        log.totalQty,
        log.isLargeBeads ? 0 : log.damagedQty,
        log.isLargeBeads ? log.totalQty : log.goodQty,
        log.shift,
        log.isLargeBeads ? '-' : log.avgWetWeight.toFixed(3),
        log.isLargeBeads ? '-' : log.dryWeight.toFixed(3),
        log.totalProdWeight.toFixed(2),
        log.isLargeBeads ? '0.00' : log.damagedWeight.toFixed(2),
        machineName,
        operatorName,
        fuelUsed,
        fuelRatio
      ].join(",");
    });

    const csvContent = "data:text/csv;charset=utf-8," + headers + "\n" + rows.join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `production_report_${new Date().toLocaleDateString()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">
      {/* Filters */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-xs font-bold text-slate-400 uppercase mb-4 tracking-wider">Report Filters</h3>
        <div className="grid grid-cols-2 md:grid-cols-6 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">From Date</label>
            <input 
              type="date"
              value={filters.dateStart}
              onChange={e => setFilters({...filters, dateStart: e.target.value})}
              className="w-full text-xs px-2 py-2 border border-slate-200 rounded"
            />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">To Date</label>
            <input 
              type="date"
              value={filters.dateEnd}
              onChange={e => setFilters({...filters, dateEnd: e.target.value})}
              className="w-full text-xs px-2 py-2 border border-slate-200 rounded"
            />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Shift</label>
            <select 
              value={filters.shift}
              onChange={e => setFilters({...filters, shift: e.target.value})}
              className="w-full text-xs px-2 py-2 border border-slate-200 rounded"
            >
              <option value="">All Shifts</option>
              <option value={Shift.Day}>Day</option>
              <option value={Shift.Night}>Night</option>
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Item</label>
            <select 
              value={filters.itemId}
              onChange={e => setFilters({...filters, itemId: e.target.value})}
              className="w-full text-xs px-2 py-2 border border-slate-200 rounded"
            >
              <option value="">All Items</option>
              {fgItems.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Machine</label>
            <select 
              value={filters.machineId}
              onChange={e => setFilters({...filters, machineId: e.target.value})}
              className="w-full text-xs px-2 py-2 border border-slate-200 rounded"
            >
              <option value="">All Machines</option>
              {machines.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
            </select>
          </div>
          <div className="flex items-end">
            <button 
              onClick={exportToExcel}
              className="w-full bg-green-700 text-white font-bold py-2 rounded text-xs hover:bg-green-800 uppercase transition-colors"
            >
              Export Excel
            </button>
          </div>
        </div>
      </div>

      {/* Production Report Table */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
          <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest">Full Detailed Production Report</h3>
          <span className="text-[10px] text-slate-400 font-bold">{filteredLogs.length} Records Found</span>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-[10px] text-left">
            <thead className="bg-slate-100 border-b border-slate-200">
              <tr>
                <th className="px-2 py-3 font-bold text-slate-500 whitespace-nowrap">Date</th>
                <th className="px-2 py-3 font-bold text-slate-500">Item</th>
                <th className="px-2 py-3 font-bold text-slate-500">UOM</th>
                <th className="px-2 py-3 font-bold text-slate-500">Prod Qty</th>
                <th className="px-2 py-3 font-bold text-slate-500">Dmg Qty</th>
                <th className="px-2 py-3 font-bold text-slate-500 text-green-700">Good Qty</th>
                <th className="px-2 py-3 font-bold text-slate-500">Shift</th>
                <th className="px-2 py-3 font-bold text-slate-500">Avg Wet</th>
                <th className="px-2 py-3 font-bold text-slate-500">Dry Wt</th>
                <th className="px-2 py-3 font-bold text-slate-500">Total Prod (kg)</th>
                <th className="px-2 py-3 font-bold text-slate-500">Total Dmg (kg)</th>
                <th className="px-2 py-3 font-bold text-slate-500">Machine</th>
                <th className="px-2 py-3 font-bold text-slate-500">Operator</th>
                <th className="px-2 py-3 font-bold text-slate-500 text-amber-700">Fuel Used</th>
                <th className="px-2 py-3 font-bold text-slate-500 text-amber-700">Fuel Ratio</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredLogs.map(log => {
                const fuelRecord = state.fuelLogs.find(f => f.date === log.date && f.shift === log.shift);
                const fuelUsed = fuelRecord ? fuelRecord.used : 0;
                const fuelRatio = log.totalProdWeight > 0 ? (fuelUsed / log.totalProdWeight).toFixed(2) : '0';
                const item = fgItems.find(i => i.id === log.itemId);
                const itemName = item?.name || (log.isLargeBeads ? 'Large Beads' : 'Unknown');
                const machineName = machines.find(m => m.id === log.machineId)?.name || '---';
                const operatorName = state.masterItems.find(o => o.id === log.operatorId)?.name || '---';

                return (
                  <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-2 py-3 text-slate-500 whitespace-nowrap">{log.date}</td>
                    <td className="px-2 py-3 font-bold text-slate-900">{itemName}</td>
                    <td className="px-2 py-3 uppercase">{log.isLargeBeads ? 'kg' : 'pcs'}</td>
                    <td className="px-2 py-3 font-bold">{log.totalQty}</td>
                    <td className="px-2 py-3 text-red-500">{log.isLargeBeads ? '0' : log.damagedQty}</td>
                    <td className="px-2 py-3 text-green-700 font-bold">{log.isLargeBeads ? log.totalQty : log.goodQty}</td>
                    <td className="px-2 py-3 font-medium">{log.shift}</td>
                    <td className="px-2 py-3">{log.isLargeBeads ? '-' : log.avgWetWeight.toFixed(3)}</td>
                    <td className="px-2 py-3">{log.isLargeBeads ? '-' : log.dryWeight.toFixed(3)}</td>
                    <td className="px-2 py-3 font-black text-blue-600">{log.totalProdWeight.toFixed(2)}</td>
                    <td className="px-2 py-3 text-red-400">{log.isLargeBeads ? '0.00' : log.damagedWeight.toFixed(2)}</td>
                    <td className="px-2 py-3">{machineName}</td>
                    <td className="px-2 py-3">{operatorName}</td>
                    <td className="px-2 py-3 font-bold text-amber-700">{fuelUsed} L</td>
                    <td className="px-2 py-3 font-bold text-amber-900">{fuelRatio}</td>
                  </tr>
                );
              })}
              {filteredLogs.length === 0 && (
                <tr>
                  <td colSpan={15} className="px-4 py-8 text-center text-slate-400 italic">No logs match the current filters.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Reports;

