          <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Yesterday Production (FG)</h3>
          <p className="text-3xl font-extrabold text-slate-900">{yesterdayFgProdWeight.toLocaleString()} kg</p>
