import React, { useState } from 'react';
import { FactoryState } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend, Label } from 'recharts';
import { TARGET_FUEL_RATIO } from '../constants';

const Efficiency: React.FC<{ state: FactoryState }> = ({ state }) => {
  const [refDate, setRefDate] = useState(new Date().toISOString().split('T')[0]);

  const filteredProd = refDate ? state.productionLogs.filter(l => l.date === new Date(refDate).toLocaleDateString()) : state.productionLogs;
  const filteredFuel = refDate ? state.fuelLogs.filter(l => l.date === new Date(refDate).toLocaleDateString()) : state.fuelLogs;

  // PIECE EFFICIENCY: Exclude Large Expanding Beads
  const pieceProd = filteredProd.filter(l => !l.isLargeBeads);
  const totalGoodPcs = pieceProd.reduce((acc, l) => acc + l.goodQty, 0);
  const totalDamagedPcs = pieceProd.reduce((acc, l) => acc + l.damagedQty, 0);
  const totalPcs = totalGoodPcs + totalDamagedPcs;
  const pieceEfficiency = totalPcs > 0 ? (totalGoodPcs / totalPcs) * 100 : 0;

  // WEIGHT EFFICIENCY: Include everything (Finished Goods Weight + Large Beads Weight)
  const totalProdWeight = filteredProd.reduce((acc, l) => acc + l.totalProdWeight, 0);
  const totalDamagedWeight = filteredProd.reduce((acc, l) => acc + l.damagedWeight, 0);
  const weightEfficiency = totalProdWeight > 0 ? ((totalProdWeight - totalDamagedWeight) / totalProdWeight) * 100 : 0;

  // FUEL RATIO: Total Fuel Consumption (Liters) / Total Production Weight (Kg)
  const totalFuelUsed = filteredFuel.reduce((acc, l) => acc + l.used, 0);
  const actualFuelRatio = totalProdWeight > 0 ? totalFuelUsed / totalProdWeight : 0;

  // Fuel Efficiency % = (Standard Ratio / Actual Ratio) * 100
  let fuelEfficiencyPercent = 0;
  if (actualFuelRatio > 0) {
    fuelEfficiencyPercent = (TARGET_FUEL_RATIO / actualFuelRatio) * 100;
  } else if (totalFuelUsed === 0 && totalProdWeight > 0) {
    fuelEfficiencyPercent = 100; // Perfect if production happened with zero fuel
  } else {
    fuelEfficiencyPercent = 0;
  }

  const COLORS = ['#10b981', '#ef4444']; // Green for Efficient, Red for Excess/Loss

  const renderEfficiencyCard = (
    value: number, 
    label: string, 
    formula: string, 
    actuals: string, 
    finalResult: string,
    isFuel: boolean = false
  ) => {
    // Determine segments for Pie Chart
    // Clamped for display, but calculations shown below are raw
    const displayValue = Math.min(Math.max(0, value), 100);
    const lossValue = 100 - displayValue;

    const data = [
      { name: isFuel ? 'Efficient Portion' : 'Efficiency', value: Number(displayValue.toFixed(1)) },
      { name: isFuel ? 'Excess Fuel Portion' : 'Loss', value: Number(lossValue.toFixed(1)) }
    ];

    return (
      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm flex flex-col items-center">
        <h4 className="text-sm font-bold text-slate-500 mb-6 uppercase tracking-widest">{label}</h4>
        <div className="w-full h-[320px] flex items-center justify-center relative">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={data}
                cx="50%"
                cy="50%"
                innerRadius={80}
                outerRadius={120}
                paddingAngle={5}
                dataKey="value"
                startAngle={90}
                endAngle={-270}
                stroke="none"
              >
                <Cell fill={COLORS[0]} />
                <Cell fill={COLORS[1]} />
                <Label
                  value={`${displayValue.toFixed(1)}%`}
                  position="center"
                  className="text-3xl font-black text-slate-800"
                />
              </Pie>
              <Tooltip />
              <Legend verticalAlign="bottom" height={36} />
            </PieChart>
          </ResponsiveContainer>
        </div>
        <div className="mt-8 w-full border-t border-slate-100 pt-6 text-center space-y-4">
          <div>
            <div className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mb-1">Formula</div>
            <div className="text-xs font-semibold text-slate-600 px-4">{formula}</div>
          </div>
          <div>
            <div className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mb-1">Actual Values</div>
            <div className="text-sm font-bold text-slate-800">{actuals}</div>
          </div>
          <div className="pt-2">
            <div className="text-lg font-black text-blue-600">{finalResult}</div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8">
      {/* Date Reference Selector */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="flex items-center space-x-4">
          <label className="text-sm font-bold text-slate-700 whitespace-nowrap">Analysis Date Filter:</label>
          <input 
            type="date" 
            value={refDate} 
            onChange={e => setRefDate(e.target.value)} 
            className="px-4 py-2 border border-slate-300 rounded-md text-sm focus:ring-2 focus:ring-blue-500 outline-none" 
          />
        </div>
        <div className="text-xs font-medium text-slate-500 bg-slate-50 px-3 py-2 rounded-full border border-slate-100">
          Showing data for: <span className="text-blue-600 font-bold">{refDate ? new Date(refDate).toLocaleDateString() : 'Global History'}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* 1. Piece Efficiency */}
        {renderEfficiencyCard(
          pieceEfficiency, 
          "Piece Efficiency", 
          "Good Pieces / Total Pieces", 
          `${totalGoodPcs.toLocaleString()} / ${totalPcs.toLocaleString()} Pcs`, 
          `${pieceEfficiency.toFixed(1)}% Efficiency`
        )}

        {/* 2. Weight Efficiency */}
        {renderEfficiencyCard(
          weightEfficiency, 
          "Weight Efficiency", 
          "(Total Weight - Damaged Weight) / Total Weight", 
          `(${totalProdWeight.toFixed(2)} - ${totalDamagedWeight.toFixed(2)}) / ${totalProdWeight.toFixed(2)} Kg`, 
          `${weightEfficiency.toFixed(1)}% Efficiency`
        )}

        {/* 3. Fuel Consumption Ratio */}
        {renderEfficiencyCard(
          fuelEfficiencyPercent, 
          "Fuel Consumption Ratio", 
          "Total Fuel Used (L) / (FG Weight + Large Beads Weight) (Kg)", 
          `${totalFuelUsed.toLocaleString()} L / ${totalProdWeight.toLocaleString()} Kg`, 
          `${actualFuelRatio.toFixed(3)} L per Kg`,
          true
        )}
      </div>

      {/* Fuel Ratio Detailed Breakdown */}
      <div className="bg-slate-900 text-white p-8 rounded-xl shadow-lg grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-8 items-center">
        <div className="flex flex-col border-r border-slate-800 pr-4">
          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Total Fuel Used</span>
          <span className="text-2xl font-black">{totalFuelUsed.toLocaleString()} <span className="text-xs font-normal text-slate-500">Liters</span></span>
        </div>
        <div className="flex flex-col border-r border-slate-800 pr-4">
          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Total Prod. Weight</span>
          <span className="text-2xl font-black">{totalProdWeight.toLocaleString()} <span className="text-xs font-normal text-slate-500">Kg</span></span>
        </div>
        <div className="flex flex-col border-r border-slate-800 pr-4">
          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Actual Fuel Ratio</span>
          <span className="text-2xl font-black text-blue-400">{actualFuelRatio.toFixed(4)} <span className="text-xs font-normal text-slate-500">L/kg</span></span>
        </div>
        <div className="flex flex-col border-r border-slate-800 pr-4">
          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Standard Benchmark</span>
          <span className="text-2xl font-black text-slate-500">{TARGET_FUEL_RATIO} <span className="text-xs font-normal text-slate-500">L/kg</span></span>
        </div>
        <div className="flex flex-col">
          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Fuel Efficiency</span>
          <span className={`text-2xl font-black ${fuelEfficiencyPercent >= 100 ? 'text-green-400' : 'text-red-400'}`}>
            {fuelEfficiencyPercent.toFixed(1)}%
          </span>
        </div>
      </div>

      <div className="text-center p-4 bg-white rounded-lg border border-slate-200">
        <p className="text-[10px] text-slate-400 uppercase font-bold tracking-widest mb-1">Calculation Disclaimers</p>
        <p className="text-[10px] text-slate-500 italic">
          * Piece Efficiency excludes Large Expanding Beads. Weight Efficiency and Fuel Ratio include ALL production types. 
          Standard Fuel Benchmark is set at {TARGET_FUEL_RATIO} L/kg.
        </p>
