import React, { useState } from 'react';
import { FactoryState, PreExpandingEntry, Shift } from '../types';
import { createAuditLog } from '../store';
import { PRE_EXPANDER_MACHINES, SHIFTS, MAX_SILO_CAPACITY } from '../constants';

const PreExpanding: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState({
    date: new Date().toISOString().split('T')[0],
    shift: Shift.Day,
    machine: PRE_EXPANDER_MACHINES[0],
    materialId: '',
    operatorId: '',
    quantityKg: 0,
    outputSiloId: 1
  });

  const rawMaterials = state.masterItems.filter(i => i.category === 'Raw Material');
  const operators = state.masterItems.filter(i => i.category === 'Operator');

  const handleProcess = () => {
    if (!form.materialId || !form.operatorId || form.quantityKg <= 0 || !form.date) {
      alert('Fill all required fields!');
      return;
    }

    const roundedQty = Number(Number(form.quantityKg).toFixed(3));

    updateState(prev => {
      let newState = { ...prev };
      const formattedDate = new Date(form.date).toLocaleDateString();

      // Reverse old entry
      if (editingId) {
        const old = prev.preExpandingLogs.find(l => l.id === editingId);
        if (old) {
          newState.rawMaterialStock = newState.rawMaterialStock.map(s => s.materialId === old.materialId ? { ...s, issuedKg: Number((s.issuedKg + old.quantityKg).toFixed(3)) } : s);
          newState.silos = newState.silos.map(s => s.id === old.outputSiloId ? { ...s, currentStock: Number((s.currentStock - old.quantityKg).toFixed(3)) } : s);
          newState.preExpandingLogs = newState.preExpandingLogs.filter(l => l.id !== editingId);
        }
      }

      // Check capacity
      const silo = newState.silos.find(s => s.id === form.outputSiloId);
      if (!silo || Number((silo.currentStock + roundedQty).toFixed(3)) > MAX_SILO_CAPACITY) {
        alert(`Capacity exceeded for Silo ${form.outputSiloId}!`);
        return prev;
      }

      const auditLog = createAuditLog('Pre Expanding', editingId ? 'UPDATE' : 'CREATE', '', `Pre-expanded ${roundedQty.toFixed(3)}kg into Silo ${form.outputSiloId}`);
      const entryId = editingId || crypto.randomUUID();
      const newEntry: PreExpandingEntry = { id: entryId, ...form, quantityKg: roundedQty, date: formattedDate };

      newState.rawMaterialStock = newState.rawMaterialStock.map(s => s.materialId === form.materialId ? { ...s, issuedKg: Number((s.issuedKg - roundedQty).toFixed(3)) } : s);
      newState.silos = newState.silos.map(s => s.id === form.outputSiloId ? { ...s, currentStock: Number((s.currentStock + roundedQty).toFixed(3)), materialName: rawMaterials.find(r => r.id === form.materialId)?.name || '' } : s);
      newState.preExpandingLogs = [newEntry, ...newState.preExpandingLogs];

      return { ...newState, auditLogs: [auditLog, ...newState.auditLogs] };
    });

    setForm({ ...form, quantityKg: 0 });
    setEditingId(null);
  };

  const handleDelete = (id: string) => {
    if (!confirm('Are you sure you want to delete this record? Stock will be reversed.')) return;
    updateState(prev => {
      const entry = prev.preExpandingLogs.find(l => l.id === id);
      if (!entry) return prev;
      const newRmStock = prev.rawMaterialStock.map(s => s.materialId === entry.materialId ? { ...s, issuedKg: Number((s.issuedKg + entry.quantityKg).toFixed(3)) } : s);
      const newSilos = prev.silos.map(s => s.id === entry.outputSiloId ? { ...s, currentStock: Number((s.currentStock - entry.quantityKg).toFixed(3)) } : s);
      const auditLog = createAuditLog('Pre Expanding', 'DELETE', id, 'Deleted record and reversed stock.');
      return { ...prev, preExpandingLogs: prev.preExpandingLogs.filter(l => l.id !== id), rawMaterialStock: newRmStock, silos: newSilos, auditLogs: [auditLog, ...prev.auditLogs] };
    });
  };

  const handleEdit = (entry: PreExpandingEntry) => {
    setEditingId(entry.id);
    const dateParts = entry.date.split('/');
    const isoDate = dateParts.length === 3 ? `${dateParts[2]}-${dateParts[0].padStart(2, '0')}-${dateParts[1].padStart(2, '0')}` : new Date().toISOString().split('T')[0];
    setForm({ ...entry, date: isoDate });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider">{editingId ? 'Edit' : 'New'} Process Entry</h3>
          <div className="space-y-4">
            <div><label className="block text-xs font-bold text-slate-500 mb-1">Date</label><input type="date" value={form.date} onChange={e => setForm({ ...form, date: e.target.value })} className="w-full px-4 py-2 border border-slate-300 rounded-md" /></div>
            <div className="grid grid-cols-2 gap-4">
              <div><label className="block text-xs font-bold text-slate-500 mb-1">Shift</label><select value={form.shift} onChange={e => setForm({ ...form, shift: e.target.value as Shift })} className="w-full px-4 py-2 border border-slate-300 rounded-md bg-slate-50">{SHIFTS.map(s => <option key={s} value={s}>{s}</option>)}</select></div>
              <div><label className="block text-xs font-bold text-slate-500 mb-1">Machine</label><select value={form.machine} onChange={e => setForm({ ...form, machine: e.target.value })} className="w-full px-4 py-2 border border-slate-300 rounded-md bg-slate-50">{PRE_EXPANDER_MACHINES.map(m => <option key={m} value={m}>{m}</option>)}</select></div>
            </div>
            <div><label className="block text-xs font-bold text-slate-500 mb-1">Raw Material</label><select value={form.materialId} onChange={e => setForm({ ...form, materialId: e.target.value })} className="w-full px-4 py-2 border border-slate-300 rounded-md"><option value="">-- Select Material --</option>{rawMaterials.map(rm => <option key={rm.id} value={rm.id}>{rm.name}</option>)}</select></div>
            <div className="grid grid-cols-2 gap-4">
              <div><label className="block text-xs font-bold text-slate-500 mb-1">Quantity (kg)</label><input type="number" step="0.001" value={form.quantityKg} onChange={e => setForm({ ...form, quantityKg: Number(e.target.value) })} className="w-full px-4 py-2 border border-slate-300 rounded-md" /></div>
              <div><label className="block text-xs font-bold text-slate-500 mb-1">Output Silo</label><select value={form.outputSiloId} onChange={e => setForm({ ...form, outputSiloId: Number(e.target.value) })} className="w-full px-4 py-2 border border-slate-300 rounded-md">{state.silos.map(s => <option key={s.id} value={s.id}>Silo {s.id}</option>)}</select></div>
            </div>
            <div className="flex space-x-4"><button onClick={handleProcess} className="flex-1 py-4 bg-slate-800 text-white font-bold rounded-md uppercase tracking-wide">{editingId ? 'Update' : 'Start'} Pre-Expanding</button>{editingId && <button onClick={() => setEditingId(null)} className="px-8 bg-slate-200 text-slate-700 font-bold rounded-md uppercase tracking-wide">Cancel</button>}</div>
          </div>
        </div>
        <div className="bg-slate-900 p-8 rounded-xl text-white"><h3 className="text-sm font-bold text-slate-400 mb-6 uppercase tracking-wider">Stock Status</h3><div className="space-y-4">{state.rawMaterialStock.map(rm => (<div key={rm.materialId} className="flex justify-between items-center border-b border-slate-800 pb-3"><div><div className="text-sm font-bold">{rm.materialName}</div><div className="text-[10px] text-slate-500 uppercase tracking-widest mt-1">Issued for expanding</div></div><div className="text-right"><div className="text-xl font-extrabold text-blue-400">{rm.issuedKg.toFixed(3)} kg</div></div></div>))}</div></div>
      </div>

      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">Historical Logs</h3>
        <div className="overflow-x-auto"><table className="w-full text-left text-xs">
          <thead className="bg-slate-50"><tr><th className="px-4 py-3">Date</th><th className="px-4 py-3">Machine</th><th className="px-4 py-3">Silo</th><th className="px-4 py-3">Qty</th><th className="px-4 py-3 text-right">Actions</th></tr></thead>
          <tbody className="divide-y divide-slate-100">{state.preExpandingLogs.map(log => (<tr key={log.id} className="hover:bg-slate-50"><td className="px-4 py-3">{log.date}</td><td className="px-4 py-3">{log.machine}</td><td className="px-4 py-3">Silo {log.outputSiloId}</td><td className="px-4 py-3 font-bold">{log.quantityKg.toFixed(3)} kg</td><td className="px-4 py-3 text-right space-x-2"><button onClick={() => handleEdit(log)} className="text-blue-600 font-bold uppercase tracking-tight hover:underline">Edit</button><button onClick={() => handleDelete(log.id)} className="text-red-600 font-bold uppercase tracking-tight hover:underline">Delete</button></td></tr>))}</tbody>
        </table></div>
      </div>
    </div>
  );
};

export default PreExpanding;

import React, { useState } from 'react';
import { FactoryState, Shift, ProductionEntry } from '../types';
import { createAuditLog } from '../store';
import { SHIFTS, DRY_WEIGHT_RATIO } from '../constants';

const Production: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState({
    date: new Date().toISOString().split('T')[0],
    shift: Shift.Day,
    machineId: '',
    operatorId: '',
    siloId: 5,
    itemId: '',
    totalQty: 0,
    damagedQty: 0,
    avgWetWeight: 0,
    isLargeBeads: false
  });

  const fgItems = state.masterItems.filter(i => i.category === 'Finished Goods');
  const operators = state.masterItems.filter(i => i.category === 'Operator');
  const machines = state.masterItems.filter(i => i.category === 'Production Machine');

  // Auto-calculated good quantity for Finished Goods
  const goodQty = form.isLargeBeads ? 0 : Math.max(0, form.totalQty - form.damagedQty);

  const handleProduction = () => {
    if (!form.operatorId || !form.machineId || !form.itemId || !form.date) {
      alert('Required fields missing, including date!');
      return;
    }
    if (form.totalQty <= 0) {
      alert(form.isLargeBeads ? 'Total Quantity (kg) must be greater than zero.' : 'Total Quantity (Pieces) must be greater than zero.');
      return;
    }

    if (!form.isLargeBeads && form.damagedQty > form.totalQty) {
      alert('Damaged Quantity cannot exceed Total Quantity.');
      return;
    }

    let dryWeight = 0;
    let totalProdWeight = 0;
    let damagedWeight = 0;

    if (form.isLargeBeads) {
      // B. LARGE EXPANDING BEADS (Kg)
      totalProdWeight = Number(Number(form.totalQty).toFixed(3));
      damagedWeight = 0;
      dryWeight = 0; // Not applicable
    } else {
      // A. FINISHED GOODS (Pieces)
      dryWeight = Number((form.avgWetWeight * DRY_WEIGHT_RATIO).toFixed(3));
      totalProdWeight = Number((form.totalQty * dryWeight).toFixed(3));
      damagedWeight = Number((form.damagedQty * dryWeight).toFixed(3));
    }

    const silo = state.silos.find(s => s.id === form.siloId);
    if (!silo || silo.currentStock < totalProdWeight) {
      alert(`Insufficient stock in Silo ${form.siloId}! Needs ${totalProdWeight.toFixed(3)}kg`);
      return;
    }

    updateState(prev => {
      let newState = { ...prev };

      // If editing, reverse the previous entry's stock changes
      if (editingId) {
        const oldEntry = prev.productionLogs.find(l => l.id === editingId);
        if (oldEntry) {
          newState.silos = newState.silos.map(s => s.id === oldEntry.siloId ? { ...s, currentStock: Number((s.currentStock + oldEntry.totalProdWeight).toFixed(3)) } : s);
          if (!oldEntry.isLargeBeads) {
            newState.fgStock = newState.fgStock.map(s => s.itemId === oldEntry.itemId ? { ...s, stockPieces: s.stockPieces - oldEntry.goodQty, totalWeight: Number((s.totalWeight - (oldEntry.goodQty * oldEntry.dryWeight)).toFixed(3)) } : s);
          }
          newState.productionLogs = newState.productionLogs.filter(l => l.id !== editingId);
        }
      }

      const formattedDate = new Date(form.date).toLocaleDateString();
      const entry: ProductionEntry = {
        id: editingId || crypto.randomUUID(),
        ...form,
        date: formattedDate,
        goodQty,
        dryWeight,
        totalProdWeight,
        damagedWeight
      };

      // Apply new stock changes
      newState.silos = newState.silos.map(s => s.id === form.siloId ? { ...s, currentStock: Number((s.currentStock - totalProdWeight).toFixed(3)) } : s);
      if (!form.isLargeBeads) {
        newState.fgStock = newState.fgStock.map(s => s.itemId === form.itemId ? { ...s, stockPieces: s.stockPieces + goodQty, totalWeight: Number((s.totalWeight + (goodQty * dryWeight)).toFixed(3)) } : s);
      }

      const logMsg = `${editingId ? 'Updated' : 'Recorded'} Production: ${form.totalQty} ${form.isLargeBeads ? 'kg' : 'pcs'} on ${formattedDate}`;
      const auditLog = createAuditLog('Production', editingId ? 'UPDATE' : 'CREATE', '', logMsg);

      return {
        ...newState,
        productionLogs: [entry, ...newState.productionLogs],
        auditLogs: [auditLog, ...newState.auditLogs]
      };
    });

    // Reset relevant fields
    setForm({ ...form, totalQty: 0, damagedQty: 0, avgWetWeight: 0 });
    setEditingId(null);
  };

  const handleDelete = (id: string) => {
    if (!confirm('Are you sure you want to delete this record? Stock will be reversed.')) return;
    updateState(prev => {
      const entry = prev.productionLogs.find(l => l.id === id);
      if (!entry) return prev;

      const newSilos = prev.silos.map(s => s.id === entry.siloId ? { ...s, currentStock: Number((s.currentStock + entry.totalProdWeight).toFixed(3)) } : s);
      let newFgStock = [...prev.fgStock];
      if (!entry.isLargeBeads) {
        newFgStock = prev.fgStock.map(s => s.itemId === entry.itemId ? { ...s, stockPieces: s.stockPieces - entry.goodQty, totalWeight: Number((s.totalWeight - (entry.goodQty * entry.dryWeight)).toFixed(3)) } : s);
      }

      const auditLog = createAuditLog('Production', 'DELETE', `ID: ${id}`, 'Deleted record and reversed stock.');

      return {
        ...prev,
        productionLogs: prev.productionLogs.filter(l => l.id !== id),
        silos: newSilos,
        fgStock: newFgStock,
        auditLogs: [auditLog, ...prev.auditLogs]
      };
    });
  };

  const handleEdit = (entry: ProductionEntry) => {
    setEditingId(entry.id);
    const dateParts = entry.date.split('/');
    const isoDate = dateParts.length === 3 ? `${dateParts[2]}-${dateParts[0].padStart(2, '0')}-${dateParts[1].padStart(2, '0')}` : new Date().toISOString().split('T')[0];
    setForm({
      date: isoDate,
      shift: entry.shift,
      machineId: entry.machineId,
      operatorId: entry.operatorId,
      siloId: entry.siloId,
      itemId: entry.itemId,
      totalQty: entry.totalQty,
      damagedQty: entry.damagedQty,
      avgWetWeight: entry.avgWetWeight,
      isLargeBeads: entry.isLargeBeads
    });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="space-y-8">
      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider">{editingId ? 'Edit' : 'New'} Production Entry</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Production Date</label>
            <input type="date" required value={form.date} onChange={e => setForm({ ...form, date: e.target.value })} className="w-full px-4 py-2 border border-slate-300 rounded-md shadow-inner" />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Shift</label>
            <select value={form.shift} onChange={e => setForm({...form, shift: e.target.value as Shift})} className="w-full px-4 py-2 border border-slate-300 rounded shadow-inner">
              {SHIFTS.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Machine</label>
            <select value={form.machineId} onChange={e => setForm({...form, machineId: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded shadow-inner">
              <option value="">-- Select --</option>
              {machines.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Operator</label>
            <select value={form.operatorId} onChange={e => setForm({...form, operatorId: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded shadow-inner">
              <option value="">-- Select --</option>
              {operators.map(o => <option key={o.id} value={o.id}>{o.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Source Silo</label>
            <select value={form.siloId} onChange={e => setForm({...form, siloId: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded shadow-inner">
              {state.silos.filter(s => s.id !== 10).map(s => <option key={s.id} value={s.id}>Silo {s.id} ({s.currentStock.toFixed(3)}kg)</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1 uppercase tracking-widest">Production Type</label>
            <div className="flex items-center space-x-4 h-[42px]">
              <label className="flex items-center space-x-2 text-sm font-medium">
                <input type="radio" checked={!form.isLargeBeads} onChange={() => setForm({...form, isLargeBeads: false, totalQty: 0, damagedQty: 0, avgWetWeight: 0})} />
                <span>Finished Goods</span>
              </label>
              <label className="flex items-center space-x-2 text-sm font-medium">
                <input type="radio" checked={form.isLargeBeads} onChange={() => setForm({...form, isLargeBeads: true, totalQty: 0, damagedQty: 0, avgWetWeight: 0})} />
                <span>Large Beads</span>
              </label>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 border-t border-slate-100 pt-8">
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">Item Selection</label>
            <select value={form.itemId} onChange={e => setForm({...form, itemId: e.target.value})} className="w-full px-4 py-2 border border-slate-300 rounded shadow-inner">
              <option value="">-- Select Item --</option>
              {fgItems.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1">
              {form.isLargeBeads ? 'Total Quantity (kg)' : 'Total Quantity (Pieces)'}
            </label>
            <input type="number" step="0.001" value={form.totalQty} onChange={e => setForm({...form, totalQty: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded shadow-inner" />
          </div>
          {!form.isLargeBeads && (
            <>
              <div>
                <label className="block text-xs font-bold text-slate-500 mb-1">Damaged Quantity (Pcs)</label>
                <input type="number" value={form.damagedQty} onChange={e => setForm({...form, damagedQty: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded shadow-inner" />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 mb-1">Avg Wet Weight (kg/pc)</label>
                <input type="number" step="0.001" value={form.avgWetWeight} onChange={e => setForm({...form, avgWetWeight: Number(e.target.value)})} className="w-full px-4 py-2 border border-slate-300 rounded shadow-inner" />
              </div>
            </>
          )}
        </div>

        <div className="mt-4 p-4 bg-slate-50 rounded-lg flex flex-wrap gap-8">
          {!form.isLargeBeads && (
            <>
              <div><span className="text-xs text-slate-500 font-bold uppercase tracking-widest">Good Quantity:</span><span className="ml-2 text-sm font-bold text-green-600">{goodQty} Pcs</span></div>
              {form.avgWetWeight > 0 && (
                <>
                  <div><span className="text-xs text-slate-500 font-bold uppercase tracking-widest">Dry Weight:</span><span className="ml-2 text-sm font-bold text-blue-600">{(form.avgWetWeight * DRY_WEIGHT_RATIO).toFixed(3)} kg</span></div>
                  <div><span className="text-xs text-slate-500 font-bold uppercase tracking-widest">Total Weight:</span><span className="ml-2 text-sm font-bold text-blue-600">{(form.totalQty * (form.avgWetWeight * DRY_WEIGHT_RATIO)).toFixed(3)} kg</span></div>
                </>
              )}
            </>
          )}
          {form.isLargeBeads && form.totalQty > 0 && (
            <div><span className="text-xs text-slate-500 font-bold uppercase tracking-widest">Total Production Weight:</span><span className="ml-2 text-sm font-bold text-blue-600">{form.totalQty.toFixed(3)} kg</span></div>
          )}
        </div>

        <div className="mt-8 flex space-x-4">
          <button onClick={handleProduction} className="flex-1 py-4 bg-slate-900 text-white font-bold rounded-md hover:bg-black uppercase tracking-widest transition-all">
            {editingId ? 'Update Record' : 'Record Production Entry'}
          </button>
          {editingId && (
            <button 
              onClick={() => {
                setEditingId(null); 
                setForm({...form, totalQty: 0, damagedQty: 0, avgWetWeight: 0});
              }} 
              className="px-8 py-4 bg-slate-200 text-slate-700 font-bold rounded-md hover:bg-slate-300 uppercase tracking-widest transition-all"
            >
              Cancel
            </button>
          )}
        </div>
      </div>

      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">Production Records</h3>
        <div className="overflow-x-auto">
          <table className="w-full text-left text-xs">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-4 py-3">Date</th>
                <th className="px-4 py-3">Item</th>
                <th className="px-4 py-3">Machine</th>
                <th className="px-4 py-3">Type</th>
                <th className="px-4 py-3">Total Qty</th>
                <th className="px-4 py-3">Good/Dmg</th>
                <th className="px-4 py-3">Weight (kg)</th>
                <th className="px-4 py-3 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.productionLogs.map(log => {
                const item = fgItems.find(i => i.id === log.itemId);
                return (
                  <tr key={log.id} className="hover:bg-slate-50">
                    <td className="px-4 py-3">{log.date}</td>
                    <td className="px-4 py-3 font-medium">{item?.name}</td>
                    <td className="px-4 py-3">{machines.find(m => m.id === log.machineId)?.name}</td>
                    <td className="px-4 py-3">
                      <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${log.isLargeBeads ? 'bg-amber-100 text-amber-700' : 'bg-blue-100 text-blue-700'}`}>
                        {log.isLargeBeads ? 'Large Beads' : 'Finished Goods'}
                      </span>
                    </td>
                    <td className="px-4 py-3">{log.isLargeBeads ? log.totalQty.toFixed(3) : log.totalQty} {log.isLargeBeads ? 'kg' : 'pcs'}</td>
                    <td className="px-4 py-3">
                      {log.isLargeBeads ? '-' : `${log.goodQty} / ${log.damagedQty}`}
                    </td>
                    <td className="px-4 py-3 font-bold">{log.totalProdWeight.toFixed(3)}</td>
                    <td className="px-4 py-3 text-right space-x-3">
                      <button onClick={() => handleEdit(log)} className="text-blue-600 hover:text-blue-800 font-bold uppercase tracking-tight">Edit</button>
                      <button onClick={() => handleDelete(log.id)} className="text-red-600 hover:text-red-800 font-bold uppercase tracking-tight">Delete</button>
                    </td>
                  </tr>
                );
              })}
              {state.productionLogs.length === 0 && (
                <tr>
                  <td colSpan={8} className="px-4 py-8 text-center text-slate-400 italic">No production records found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Production;

import React, { useState } from 'react';
import { FactoryState, Shift } from '../types';

const Reports: React.FC<{ state: FactoryState }> = ({ state }) => {
  const [filters, setFilters] = useState({
    dateStart: '',
    dateEnd: '',
    shift: '',
    itemId: '',
    machineId: ''
  });

  const fgItems = state.masterItems.filter(i => i.category === 'Finished Goods');
  const machines = state.masterItems.filter(i => i.category === 'Production Machine');

  const filteredLogs = state.productionLogs.filter(log => {
    if (filters.shift && log.shift !== filters.shift) return false;
    if (filters.itemId && log.itemId !== filters.itemId) return false;
    if (filters.machineId && log.machineId !== filters.machineId) return false;

    // Strict date range filtering
    if (filters.dateStart || filters.dateEnd) {
      const logDate = new Date(log.date).getTime();
      if (filters.dateStart && logDate < new Date(filters.dateStart).getTime()) return false;
      if (filters.dateEnd && logDate > new Date(filters.dateEnd).getTime()) return false;
    }
    return true;
  });

  const exportToExcel = () => {
    const headers = [
      "Date", "Item", "UOM", "Production Qty", "Damaged Qty", "Good Qty", 
      "Shift", "Average Wet Weight", "Dry Weight", "Total Production Weight", "Total Damaged Weight", 
      "Machine", "Operator", "Fuel Used", "Fuel Ratio"
    ].join(",");

    const rows = filteredLogs.map(log => {
      const fuelRecord = state.fuelLogs.find(f => f.date === log.date && f.shift === log.shift);
      const fuelUsed = fuelRecord ? fuelRecord.used : 0;
      const fuelRatio = log.totalProdWeight > 0 ? (fuelUsed / log.totalProdWeight).toFixed(3) : '0.000';
      const item = fgItems.find(i => i.id === log.itemId);
      const itemName = item?.name || (log.isLargeBeads ? 'Large Beads' : 'Unknown');
      const machineName = machines.find(m => m.id === log.machineId)?.name || '---';
      const operatorName = state.masterItems.find(o => o.id === log.operatorId)?.name || '---';

      return [
        log.date,
        itemName,
        log.isLargeBeads ? 'kg' : 'pcs',
        log.totalQty,
        log.isLargeBeads ? 0 : log.damagedQty,
        log.isLargeBeads ? log.totalQty : log.goodQty,
        log.shift,
        log.isLargeBeads ? '-' : log.avgWetWeight.toFixed(3),
        log.isLargeBeads ? '-' : log.dryWeight.toFixed(3),
        log.totalProdWeight.toFixed(3),
        log.isLargeBeads ? '0.000' : log.damagedWeight.toFixed(3),
        machineName,
        operatorName,
        fuelUsed.toFixed(3),
        fuelRatio
      ].join(",");
    });

    const csvContent = "data:text/csv;charset=utf-8," + headers + "\n" + rows.join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `production_report_${new Date().toLocaleDateString()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">
      {/* Filters */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-xs font-bold text-slate-400 uppercase mb-4 tracking-wider">Report Filters</h3>
        <div className="grid grid-cols-2 md:grid-cols-6 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">From Date</label>
            <input 
              type="date"
              value={filters.dateStart}
              onChange={e => setFilters({...filters, dateStart: e.target.value})}
              className="w-full text-xs px-2 py-2 border border-slate-200 rounded"
            />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">To Date</label>
            <input 
              type="date"
              value={filters.dateEnd}
              onChange={e => setFilters({...filters, dateEnd: e.target.value})}
              className="w-full text-xs px-2 py-2 border border-slate-200 rounded"
            />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Shift</label>
            <select 
              value={filters.shift}
              onChange={e => setFilters({...filters, shift: e.target.value})}
              className="w-full text-xs px-2 py-2 border border-slate-200 rounded"
            >
              <option value="">All Shifts</option>
              <option value={Shift.Day}>Day</option>
              <option value={Shift.Night}>Night</option>
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Item</label>
            <select 
              value={filters.itemId}
              onChange={e => setFilters({...filters, itemId: e.target.value})}
              className="w-full text-xs px-2 py-2 border border-slate-200 rounded"
            >
              <option value="">All Items</option>
              {fgItems.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Machine</label>
            <select 
              value={filters.machineId}
              onChange={e => setFilters({...filters, machineId: e.target.value})}
              className="w-full text-xs px-2 py-2 border border-slate-200 rounded"
            >
              <option value="">All Machines</option>
              {machines.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
            </select>
          </div>
          <div className="flex items-end">
            <button 
              onClick={exportToExcel}
              className="w-full bg-green-700 text-white font-bold py-2 rounded text-xs hover:bg-green-800 uppercase transition-colors tracking-widest"
            >
              Export Excel
            </button>
          </div>
        </div>
      </div>

      {/* Production Report Table */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
          <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest">Full Detailed Production Report</h3>
          <span className="text-[10px] text-slate-400 font-bold uppercase">{filteredLogs.length} Records Found</span>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-[10px] text-left">
            <thead className="bg-slate-100 border-b border-slate-200">
              <tr>
                <th className="px-2 py-3 font-bold text-slate-500 whitespace-nowrap uppercase">Date</th>
                <th className="px-2 py-3 font-bold text-slate-500 uppercase">Item</th>
                <th className="px-2 py-3 font-bold text-slate-500 uppercase">UOM</th>
                <th className="px-2 py-3 font-bold text-slate-500 uppercase">Prod Qty</th>
                <th className="px-2 py-3 font-bold text-slate-500 uppercase">Dmg Qty</th>
                <th className="px-2 py-3 font-bold text-green-700 uppercase">Good Qty</th>
                <th className="px-2 py-3 font-bold text-slate-500 uppercase">Shift</th>
                <th className="px-2 py-3 font-bold text-slate-500 uppercase">Avg Wet</th>
                <th className="px-2 py-3 font-bold text-slate-500 uppercase">Dry Wt</th>
                <th className="px-2 py-3 font-bold text-slate-500 uppercase">Total Prod (kg)</th>
                <th className="px-2 py-3 font-bold text-slate-500 uppercase">Total Dmg (kg)</th>
                <th className="px-2 py-3 font-bold text-slate-500 uppercase">Machine</th>
                <th className="px-2 py-3 font-bold text-slate-500 uppercase">Operator</th>
                <th className="px-2 py-3 font-bold text-amber-700 uppercase">Fuel Used</th>
                <th className="px-2 py-3 font-bold text-amber-700 uppercase">Fuel Ratio</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredLogs.map(log => {
                const fuelRecord = state.fuelLogs.find(f => f.date === log.date && f.shift === log.shift);
                const fuelUsed = fuelRecord ? fuelRecord.used : 0;
                const fuelRatio = log.totalProdWeight > 0 ? (fuelUsed / log.totalProdWeight).toFixed(3) : '0.000';
                const item = fgItems.find(i => i.id === log.itemId);
                const itemName = item?.name || (log.isLargeBeads ? 'Large Beads' : 'Unknown');
                const machineName = machines.find(m => m.id === log.machineId)?.name || '---';
                const operatorName = state.masterItems.find(o => o.id === log.operatorId)?.name || '---';

                return (
                  <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-2 py-3 text-slate-500 whitespace-nowrap">{log.date}</td>
