              })}
              {filteredLogs.length === 0 && (
                <tr>
                  <td colSpan={15} className="px-4 py-8 text-center text-slate-400 italic">No logs match the current filters.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

