import React, { useState } from 'react';
import { FactoryState, DeliveryEntry } from '../types';
import { createAuditLog } from '../store';

const Delivery: React.FC<{ state: FactoryState; updateState: (updater: (prev: FactoryState) => FactoryState) => void }> = ({ state, updateState }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState({
    date: new Date().toISOString().split('T')[0],
    itemId: '',
    quantity: 0,
    remarks: ''
  });

  const fgItems = state.masterItems.filter(i => i.category === 'Finished Goods');
  const items = [
    { id: 'large_beads', name: 'Large Expanding Beads', type: 'Large Beads' },
    ...fgItems.map(i => ({ id: i.id, name: i.name, type: 'Finished Goods' }))
  ];

  const handleDelivery = () => {
    if (!form.date || !form.itemId || form.quantity <= 0) {
      alert('Please fill all required fields: Date, Item, and Quantity.');
      return;
    }

    const selectedItem = items.find(i => i.id === form.itemId);
    const isLargeBeads = form.itemId === 'large_beads';
    const roundedQty = isLargeBeads ? Number(Number(form.quantity).toFixed(3)) : Math.floor(form.quantity);

    updateState(prev => {
      let newState = { ...prev };
      const formattedDate = new Date(form.date).toLocaleDateString();

      // 1. REVERSE STOCK IF EDITING
      if (editingId) {
        const old = prev.deliveryLogs.find(l => l.id === editingId);
        if (old) {
          if (old.itemId === 'large_beads') {
            newState.silos = newState.silos.map(s => s.id === 5 ? { ...s, currentStock: Number((s.currentStock + old.quantity).toFixed(3)) } : s);
          } else {
            newState.fgStock = newState.fgStock.map(s => s.itemId === old.itemId ? { ...s, stockPieces: s.stockPieces + old.quantity } : s);
          }
          newState.deliveryLogs = newState.deliveryLogs.filter(l => l.id !== editingId);
        }
      }

      // 2. VALIDATE NEW STOCK
      if (isLargeBeads) {
        const silo5 = newState.silos.find(s => s.id === 5);
        if (!silo5 || silo5.currentStock < roundedQty) {
          alert('Insufficient stock in Silo 5');
          return prev;
        }
      } else {
        const stock = newState.fgStock.find(s => s.itemId === form.itemId);
        if (!stock || stock.stockPieces < roundedQty) {
          alert('Insufficient finished goods stock');
          return prev;
        }
      }

      // 3. DEDUCT STOCK
      if (isLargeBeads) {
        newState.silos = newState.silos.map(s => s.id === 5 ? { ...s, currentStock: Number((s.currentStock - roundedQty).toFixed(3)) } : s);
      } else {
        newState.fgStock = newState.fgStock.map(s => s.itemId === form.itemId ? { ...s, stockPieces: s.stockPieces - roundedQty } : s);
      }

      // 4. CREATE ENTRY
      const entryId = editingId || crypto.randomUUID();
      const newEntry: DeliveryEntry = {
        id: entryId,
        date: formattedDate,
        itemId: form.itemId,
        itemName: selectedItem?.name || 'Unknown',
        quantity: roundedQty,
        unit: isLargeBeads ? 'Kg' : 'Pieces',
        source: isLargeBeads ? 'Silo 5' : 'Finished Goods Stock',
        remarks: form.remarks,
        timestamp: new Date(form.date).getTime()
      };

      const auditLog = createAuditLog('Delivery', editingId ? 'UPDATE' : 'CREATE', '', `Delivered ${roundedQty} ${newEntry.unit} of ${newEntry.itemName}`);

      return {
        ...newState,
        deliveryLogs: [newEntry, ...newState.deliveryLogs],
        auditLogs: [auditLog, ...newState.auditLogs]
      };
    });

    setForm({ ...form, quantity: 0, remarks: '' });
    setEditingId(null);
  };

  const handleDelete = (id: string) => {
    if (!confirm('Are you sure you want to delete this delivery? Stock will be restored.')) return;
    updateState(prev => {
      const entry = prev.deliveryLogs.find(l => l.id === id);
      if (!entry) return prev;

      let newState = { ...prev };
      if (entry.itemId === 'large_beads') {
        newState.silos = newState.silos.map(s => s.id === 5 ? { ...s, currentStock: Number((s.currentStock + entry.quantity).toFixed(3)) } : s);
      } else {
        newState.fgStock = newState.fgStock.map(s => s.itemId === entry.itemId ? { ...s, stockPieces: s.stockPieces + entry.quantity } : s);
      }

      const auditLog = createAuditLog('Delivery', 'DELETE', id, `Deleted delivery and restored ${entry.quantity} ${entry.unit} of ${entry.itemName}`);
      newState.deliveryLogs = newState.deliveryLogs.filter(l => l.id !== id);
      newState.auditLogs = [auditLog, ...newState.auditLogs];

      return newState;
    });
  };

  const handleEdit = (entry: DeliveryEntry) => {
    setEditingId(entry.id);
    const dateParts = entry.date.split('/');
    const isoDate = dateParts.length === 3 ? `${dateParts[2]}-${dateParts[0].padStart(2, '0')}-${dateParts[1].padStart(2, '0')}` : entry.date;
    setForm({
      date: isoDate,
      itemId: entry.itemId,
      quantity: entry.quantity,
      remarks: entry.remarks || ''
    });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="space-y-8">
      {/* Input Form */}
      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider">{editingId ? 'Edit' : 'New'} Delivery Entry</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-6">
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1 uppercase tracking-widest">Delivery Date</label>
            <input 
              type="date" 
              value={form.date} 
              onChange={e => setForm({ ...form, date: e.target.value })} 
              className="w-full px-4 py-2 border border-slate-300 rounded-md focus:ring-2 focus:ring-blue-500 outline-none" 
            />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1 uppercase tracking-widest">Item</label>
            <select 
              value={form.itemId} 
              onChange={e => setForm({ ...form, itemId: e.target.value })} 
              className="w-full px-4 py-2 border border-slate-300 rounded-md focus:ring-2 focus:ring-blue-500 outline-none"
            >
              <option value="">-- Select Item --</option>
              {items.map(i => (
                <option key={i.id} value={i.id}>{i.name} ({i.type})</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1 uppercase tracking-widest">
              Quantity {form.itemId === 'large_beads' ? '(Kg)' : '(Pieces)'}
            </label>
            <input 
              type="number" 
              step={form.itemId === 'large_beads' ? '0.001' : '1'}
              value={form.quantity} 
              onChange={e => setForm({ ...form, quantity: Number(e.target.value) })} 
              className="w-full px-4 py-2 border border-slate-300 rounded-md focus:ring-2 focus:ring-blue-500 outline-none font-bold" 
            />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1 uppercase tracking-widest">Remarks</label>
            <input 
              type="text" 
              value={form.remarks} 
              onChange={e => setForm({ ...form, remarks: e.target.value })} 
              className="w-full px-4 py-2 border border-slate-300 rounded-md focus:ring-2 focus:ring-blue-500 outline-none" 
              placeholder="Optional notes"
            />
          </div>
        </div>

        <div className="flex space-x-4">
          <button 
            onClick={handleDelivery} 
            className="flex-1 py-4 bg-slate-900 text-white font-bold rounded-md uppercase tracking-widest hover:bg-black transition-all shadow-lg"
          >
            {editingId ? 'Update Delivery' : 'Record Delivery'}
          </button>
          {editingId && (
            <button 
              onClick={() => {
                setEditingId(null);
                setForm({ ...form, quantity: 0, remarks: '' });
              }} 
              className="px-8 bg-slate-200 text-slate-700 font-bold rounded-md uppercase tracking-widest hover:bg-slate-300 transition-all"
            >
              Cancel
            </button>
          )}
        </div>
      </div>

      {/* List Table */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">Recent Delivery Records</h3>
        <div className="overflow-x-auto">
          <table className="w-full text-left text-xs">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-4 py-3 font-bold uppercase text-slate-500">Date</th>
                <th className="px-4 py-3 font-bold uppercase text-slate-500">Item</th>
                <th className="px-4 py-3 font-bold uppercase text-slate-500">Quantity</th>
                <th className="px-4 py-3 font-bold uppercase text-slate-500">Unit</th>
                <th className="px-4 py-3 font-bold uppercase text-slate-500">Source</th>
                <th className="px-4 py-3 text-right font-bold uppercase text-slate-500">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.deliveryLogs.map(log => (
                <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-4 py-3">{log.date}</td>
                  <td className="px-4 py-3 font-bold">{log.itemName}</td>
                  <td className="px-4 py-3 font-bold text-blue-600">
                    {log.itemId === 'large_beads' ? log.quantity.toFixed(3) : log.quantity}
                  </td>
                  <td className="px-4 py-3 uppercase">{log.unit}</td>
                  <td className="px-4 py-3 text-slate-400">{log.source}</td>
                  <td className="px-4 py-3 text-right space-x-3">
                    <button onClick={() => handleEdit(log)} className="text-blue-600 font-bold uppercase hover:underline">Edit</button>
                    <button onClick={() => handleDelete(log.id)} className="text-red-600 font-bold uppercase hover:underline">Delete</button>
                  </td>
                </tr>
              ))}
              {state.deliveryLogs.length === 0 && (
                <tr>
                  <td colSpan={6} className="px-4 py-12 text-center text-slate-400 italic">No delivery records found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

